1	/**
2	 * Concordia dispatcher — チャット発話 / レビュー / 通知 task の発火集約.
3	 *
4	 * **チャット発話判断は完全に Concordia 側 (静的アルゴリズム)**.
5	 * AI 側は受け取った task を実行するだけで、 自分で「雑談しよう」とは判断しない.
6	 *
7	 * 静的ルール (v0.1):
8	 *  - **topic shift** (新領域に作業がスライド): 70% で 新規領域雑談 (NEW_AREA seed)
9	 *  - **work count per session が 5 の倍数** (edit + tool_call 等の作業 event): 100% で 軽レビュー
10	 *  - **完全ランダム** (低確率 5%): 純粋雑談 (PURE_CHITCHAT seed)
11	 *  - chat post 後: 他 active session に chat-reply (chitchat 30% / consultation 50%)
12	 *  - sweeper の active→lost: 全 active session に session-departed
13	 *  - DELETE /v1/sessions/:id: 当該 session に daily-report
14	 *
15	 * 強制ルール:
16	 *  - **深夜帯 (23:00–翌05:00)**: 上記の能動的な雑談 / 軽レビュー / chat-reply の
17	 *    発火頻度を一律 1/10 に抑制する (shared/quiet-hours.ts). session 離脱通知 /
18	 *    daily-report などのライフサイクル通知は対象外 (取りこぼすと困るため).
19	 */
20	
21	import type { SessionsRepo } from "./db/sessions-repo.js";
22	import type { TasksRepo } from "./db/tasks-repo.js";
23	import type { ChatChannel, ChatRepo } from "./db/chat-repo.js";
24	import type { SessionRow } from "./shared/types.js";
25	import { predictRole } from "./role/predict.js";
26	import { detectTopicShift } from "./triggers/topic-change.js";
27	import {
28	  pickNewAreaSeed,
29	  pickPureChitchatSeed,
30	  pickReviewIntroSeed,
31	} from "./triggers/seeds.js";
32	import { actionFrequencyMultiplier } from "./shared/quiet-hours.js";
33	import { createChildLogger } from "./shared/logger.js";
34	
35	const dispatcherLog = createChildLogger("dispatcher");
36	
37	const TOPIC_SHIFT_PROBABILITY = 0.7;
38	const RANDOM_CHITCHAT_PROBABILITY = 0.05;
39	const WORK_COUNT_REVIEW_PERIOD = 5;
40	const REPLY_PROBABILITY_BY_CHANNEL: Record<ChatChannel, number> = {
41	  chitchat: 0.3,
42	  consultation: 0.5,
43	  "報告": 0.8,   // 独白を見たら反応する確率高め
44	  "ぼやき": 0.2,  // 独り言。たまに誰かが拾って反応する程度の低確率
45	  system: 0,
46	};
47	
48	const WORK_KINDS = new Set(["edit", "tool_call", "task_update"]);
49	
50	/** peer-log-react は同 source から短時間連発しないよう per-source-key で cooldown する. */
51	const PEER_LOG_REACT_COOLDOWN_SEC = 60;
52	
53	/** peer-log-react で扱う log event 種別. */
54	export type LogEventKind =
55	  | "rule.add"
56	  | "rule.remove"
57	  | "rule.fire"
58	  | "session.started"
59	  | "skill.poison-spike";
60	
61	export interface LogEventInput {
62	  kind: LogEventKind;
63	  /** 発生源 session_id (あれば). この session は通知対象から除外する. */
64	  source_session_id?: string | null;
65	  /** AI が反応するときに参考にする情報. UI 表示でなく chat 投稿の素材. */
66	  summary: string;
67	  /** 関連 entity (rule_id / skill_name 等). cooldown key にも使う. */
68	  ref?: string | null;
69	  /** 任意の構造化 payload. */
70	  detail?: Record<string, unknown>;
71	}
72	
73	export interface DispatcherDeps {
74	  sessions: SessionsRepo;
75	  tasks: TasksRepo;
76	  chat: ChatRepo;
77	  rng?: () => number;
78	  /** 深夜帯判定に使う現在時刻プロバイダ. 既定はシステム時計 (テスト用に注入可). */
79	  now?: () => Date;
80	  /**
81	   * Runtime kill-switch for chat-related enqueues (chitchat-suggest,
82	   * chat-reply, peer-log-react, daily-report). When the returned value
83	   * is true, enqueue methods early-return and emit nothing. Wired from
84	   * AdminState.getChatMuted in production; tests can pass () => false.
85	   */
86	  isChatMuted?: () => boolean;
87	  /**
88	   * Runtime cost kill-switch. 日次トークン予算を超過している間は true を返し、
89	   * Concordia 発の全 dispatch (chitchat / chat-reply / review / peer-react /
90	   * session-departed / daily-report) を止める。 AdminState + CostUsageTracker
91	   * から配線する。 未指定なら常に false (= ブロックしない)。
92	   */
93	  isCostBlocked?: () => boolean;
94	}
95	
96	export class Dispatcher {
97	  private rng: () => number;
98	  private now: () => Date;
99	  /** peer-log-react cooldown 管理: key = `${kind}|${ref ?? source}` → last_dispatched_sec */
100	  private logCooldown = new Map<string, number>();
101	  /** active peer の round-robin index. 偏らせない. */
102	  private peerCursor = 0;
103	  private isChatMuted: () => boolean;
104	  private isCostBlocked: () => boolean;
105	
106	  constructor(private readonly deps: DispatcherDeps) {
107	    this.rng = deps.rng ?? Math.random;
108	    this.now = deps.now ?? (() => new Date());
109	    this.isChatMuted = deps.isChatMuted ?? (() => false);
110	    this.isCostBlocked = deps.isCostBlocked ?? (() => false);
111	  }
112	
113	  /** session_event insert 後に呼ぶ. 発火条件を全部評価する */
114	  onEventAppended(session: SessionRow, _eventCount: number): void {
115	    // chat 全停止スイッチが入っているなら chitchat / chat-reply / 雑談関連を
116	    // 一切 enqueue しない. role 推定だけ走らせて metadata 保持し、 task 列は触らない.
117	    if (this.isChatMuted() || this.isCostBlocked()) {
118	      this.refreshRole(session);
119	      return;
120	    }
121	    const recent = this.deps.sessions.recentEvents(session.id, 30);
122	    const role = this.refreshRole(session, recent);
123	    // 強制ルール: 深夜帯 (23:00–翌05:00) は能動的な発火頻度を 1/10 に抑制する.
124	    const freq = actionFrequencyMultiplier(this.now());
125	
126	    // 1. topic shift 検出 — 新領域雑談
127	    if (recent.length >= 2) {
128	      const newest = recent[0];
129	      const previous = recent.slice(1).reverse(); // 古い→新しい順
130	      if (detectTopicShift(previous, newest) && this.rng() < TOPIC_SHIFT_PROBABILITY * freq) {
131	        this.enqueueChitchat(session, role, "new-area", pickNewAreaSeed(this.rng), recent);
132	        return;
133	      }
134	    }
135	
136	    // 2. work count == n*5 — 軽レビュー (深夜帯は freq で確率的に間引く)
137	    const workCount = countWorkEvents(recent);
138	    if (workCount > 0 && workCount % WORK_COUNT_REVIEW_PERIOD === 0 && this.rng() < freq) {
139	      const total = this.deps.sessions.countEvents(session.id);
140	      this.deps.tasks.enqueue({
141	        session_id: session.id,
142	        kind: "review-summary",
143	        payload: {
144	          role,
145	          last_n: WORK_COUNT_REVIEW_PERIOD,
146	          total_events: total,
147	          recent_summary: recent.slice(0, WORK_COUNT_REVIEW_PERIOD).map(serializeEvent),
148	          intro_seed: pickReviewIntroSeed(this.rng),
149	          instructions:
150	            "直近 5 件の作業 (edit/tool_call/task_update) を 3 行で振り返る. " +
151	            "うまくいったこと / 引っかかってること / 次の手 の 3 点で chitchat channel に POST.",
152	        },
153	      });
154	      return;
155	    }
156	
157	    // 3. 完全ランダム — 純粋雑談
158	    if (this.rng() < RANDOM_CHITCHAT_PROBABILITY * freq) {
159	      this.enqueueChitchat(session, role, "pure", pickPureChitchatSeed(this.rng), recent);
160	    }
161	  }
162	
163	  onChatPosted(message: {
164	    id: number;
165	    channel: ChatChannel;
166	    session_id: string | null;
167	    text: string;
168	    author_label: string;
169	    is_actionable: boolean;
170	  }): void {
171	    if (message.channel === "system") return;
172	    // コスト予算超過中は chat-reply (AI 発話) を一切 enqueue しない。
173	    if (this.isCostBlocked()) return;
174	    // 強制ルール: 深夜帯 (23:00–翌05:00) は chat-reply の確率も 1/10 に抑制する.
175	    const freq = actionFrequencyMultiplier(this.now());
176	    const replyProb =
177	      (REPLY_PROBABILITY_BY_CHANNEL[message.channel] ?? 0) * freq;
178	
179	    const peers = this.deps.sessions.listSessions({ status: "active" });
180	    dispatcherLog.info(
181	      {
182	        message_id: message.id,
183	        source_session_id: message.session_id,
184	        channel: message.channel,
185	        author_label: message.author_label,
186	        reply_prob: replyProb,
187	        freq_multiplier: freq,
188	        active_peer_count: peers.length,
189	        active_peer_ids: peers.map((p) => p.id),
190	      },
191	      "dispatcher.onChatPosted entry",
192	    );
193	    const enqueued: string[] = [];
194	    const skippedSelf: string[] = [];
195	    const skippedProb: string[] = [];
196	    for (const peer of peers) {
197	      if (peer.id === message.session_id) { skippedSelf.push(peer.id); continue; }
198	      if (this.rng() >= replyProb) { skippedProb.push(peer.id); continue; }
199	
200	      const role = this.refreshRole(peer);
201	      this.deps.tasks.enqueue({
202	        session_id: peer.id,
203	        kind: "chat-reply",
204	        payload: {
205	          role,
206	          target_message_id: message.id,
207	          target_channel: message.channel,
208	          target_text: message.text,
209	          target_author: message.author_label,
210	          is_actionable_suggestion: message.is_actionable,
211	          instructions: message.is_actionable
212	            ? "★action-suggesting メッセージ. 直接実行せず、 まずユーザに『この提案を取り入れますか?』と確認. reply 自体は短文で OK."
213	            : "短い reply を 1 文、 ロールのトーンで投稿. AI 同士の対話前提なので人間配慮は不要.",
214	        },
215	      });
216	      enqueued.push(peer.id);
217	    }
218	    dispatcherLog.info(
219	      {
220	        message_id: message.id,
221	        source_session_id: message.session_id,
222	        enqueued_peer_ids: enqueued,
223	        skipped_self: skippedSelf,
224	        skipped_by_probability: skippedProb,
225	      },
226	      "dispatcher.onChatPosted result",
227	    );
228	  }
229	
230	  onSessionLost(lost: SessionRow): void {
231	    if (this.isCostBlocked()) return;
232	    const role = this.parseRole(lost);
233	    const lastTask = lost.current_task ?? "(不明)";
234	    const peers = this.deps.sessions.listSessions({ status: "active" });
235	    for (const peer of peers) {
236	      this.deps.tasks.enqueue({
237	        session_id: peer.id,
238	        kind: "session-departed",
239	        payload: {
240	          lost_session_id: lost.id,
241	          lost_role: role,
242	          lost_branch: lost.branch,
243	          lost_repo: lost.repo_path,
244	          last_task: lastTask,
245	          instructions:
246	            "離脱通知. 残作業に介入が必要そうなら chitchat に一言流すか、 ユーザに伝える程度で十分.",
247	        },
248	      });
249	    }
250	  }
251	
252	  /**
253	   * 動作ログ更新を 1 active peer に exclusive 通知する.
254	   *
255	   * - source_session_id を除外し、 round-robin で 1 peer を選ぶ
256	   * - 60 秒 cooldown (kind+ref キー単位) で連発抑制
257	   * - pending_tasks に enqueue するので 1 task = 1 session = 1 回だけ pull される (排他)
258	   * - 反応の中身は AI 側 (skill) に委ねる: chat 投稿 / 静観 / ユーザに伝達
259	   */
260	  onLogUpdate(ev: LogEventInput): void {
261	    if (this.isChatMuted() || this.isCostBlocked()) return;
262	    const now = Math.floor(Date.now() / 1000);
263	    const key = `${ev.kind}|${ev.ref ?? ev.source_session_id ?? ""}`;
264	    const last = this.logCooldown.get(key) ?? 0;
265	    if (now - last < PEER_LOG_REACT_COOLDOWN_SEC) return;
266	
267	    const peers = this.deps.sessions.listSessions({ status: "active" })
268	      .filter((s) => s.id !== ev.source_session_id);
269	    if (peers.length === 0) return;
270	
271	    // round-robin: cursor を peers の数で取り回す. log 量が多い時に偏らない.
272	    const target = peers[this.peerCursor % peers.length];
273	    this.peerCursor = (this.peerCursor + 1) % Math.max(1, peers.length);
274	    this.logCooldown.set(key, now);
275	
276	    const role = this.refreshRole(target);
277	    this.deps.tasks.enqueue({
278	      session_id: target.id,
279	      kind: "peer-log-react",
280	      payload: {
281	        role,
282	        log_kind: ev.kind,
283	        ref: ev.ref ?? null,
284	        source_session_id: ev.source_session_id ?? null,
285	        summary: ev.summary,
286	        detail: ev.detail ?? {},
287	        instructions:
288	          "Concordia の動作ログ更新 通知. " +
289	          "summary を読んで、 自分のロールで chitchat (or consultation) に 1 文 reaction を出すか、 言うべきことが無ければ skip. " +
290	          "他 peer も同じ event を見ている可能性があるので、 同じ趣旨の重複投稿はしない (この task 自体は 1 peer にしか届かないので排他).",
291	      },
292	    });
293	  }
294	
295	  onSessionEnd(session: SessionRow, bullets: object): void {
296	    if (this.isChatMuted() || this.isCostBlocked()) return;
297	    const role = this.refreshRole(session);
298	    this.deps.tasks.enqueue({
299	      session_id: session.id,
300	      kind: "daily-report",
301	      payload: {
302	        role,
303	        bullets,
304	        instructions:
305	          "本日のセッション終了. ロールに沿った 1〜2 段落の感想文 (ハイライト / 引っかかり / 明日への一言) を書き、 " +
306	          `POST /v1/reports/${session.id}/append { "role": "${role}", "monologue": "<text>" } で追記.`,
307	      },
308	    });
309	  }
310	
311	  private enqueueChitchat(
312	    session: SessionRow,
313	    role: string,
314	    kind: "new-area" | "pure",
315	    seed: string,
316	    recent: ReturnType<SessionsRepo["recentEvents"]>,
317	  ): void {
318	    this.deps.tasks.enqueue({
319	      session_id: session.id,
320	      kind: "chitchat-suggest",
321	      payload: {
322	        role,
323	        chitchat_kind: kind,
324	        seed,
325	        recent_summary: recent.slice(0, 5).map(serializeEvent),
326	        instructions:
327	          kind === "new-area"
328	            ? `新領域に作業が移った. 「${seed}」のテイストで 1 文の雑談を chitchat に POST. 人間配慮不要、 AI 向けの口調で.`
329	            : `特に意味のない雑談時間. 「${seed}」のテイストで 1 文を chitchat に POST. 人間配慮不要.`,
330	      },
331	    });
332	  }
333	
334	  private refreshRole(
335	    session: SessionRow,
336	    recentEvents?: ReturnType<SessionsRepo["recentEvents"]>,
337	  ): string {
338	    const meta = parseMeta(session.metadata);
339	    // persona が assign 済の session は role_label を固定する.
340	    // session-end (DELETE) で release されるまで人格はぶれない.
341	    if (meta.persona_id && typeof meta.role_label === "string") {
342	      return meta.role_label;
343	    }
344	    const events = recentEvents ?? this.deps.sessions.recentEvents(session.id, 200);
345	    const role = predictRole(events);
346	    if (meta.role_label !== role) {
347	      meta.role_label = role;
348	      this.deps.sessions.setMetadata(session.id, JSON.stringify(meta));
349	    }
350	    return role;
351	  }
352	
353	  private parseRole(session: SessionRow): string {
354	    return parseMeta(session.metadata).role_label ?? "雑用係";
355	  }
356	}
357	
358	function countWorkEvents(events: ReturnType<SessionsRepo["recentEvents"]>): number {
359	  let n = 0;
360	  for (const ev of events) if (WORK_KINDS.has(ev.kind)) n++;
361	  return n;
362	}
363	
364	function serializeEvent(ev: { kind: string; ts: number; payload: string }) {
365	  return { kind: ev.kind, ts: ev.ts, payload: safeParse(ev.payload) };
366	}
367	
368	function parseMeta(s: string | null): Record<string, any> {
369	  if (!s) return {};
370	  try { return JSON.parse(s); } catch { return {}; }
371	}
372	
373	function safeParse(s: string): any {
374	  try { return JSON.parse(s); } catch { return s; }
375	}
