1	import type Database from "better-sqlite3";
2	
3	export type PendingTaskKind =
4	  | "chitchat-suggest"
5	  | "chat-reply"
6	  | "review-summary"
7	  | "daily-report"
8	  | "session-departed"
9	  | "peer-log-react"
10	  | "stat-collect"
11	  | "title-suggest";
12	
13	export interface PendingTaskRow {
14	  id: number;
15	  session_id: string;
16	  kind: PendingTaskKind;
17	  payload: string; // JSON
18	  created_at: number;
19	  delivered_at: number | null;
20	  expires_at: number;
21	  /** retry 回数. 0 = 初回。 上限到達で諦める. */
22	  retries: number;
23	  /** 直近の配信試行 ts (delivered_at と同じ値か、 retry で更新). */
24	  last_attempt_at: number | null;
25	}
26	
27	const DEFAULT_TTL_SEC = 30 * 60; // 30 分
28	const DEFAULT_RETRY_AFTER_SEC = 5 * 60; // 配信後 5 分応答なしで retry 対象
29	const DEFAULT_MAX_RETRIES = 3;
30	
31	export class TasksRepo {
32	  constructor(private readonly db: Database.Database) {}
33	
34	  enqueue(input: {
35	    session_id: string;
36	    kind: PendingTaskKind;
37	    payload: object;
38	    ttlSec?: number;
39	    /** テスト用: created_at に使う epoch 秒. 省略時は Math.floor(Date.now() / 1000).
40	     *  expires_at は常に実 wall-clock ベースで計算するため、 模擬時刻を渡しても
41	     *  pull() の期限チェックには影響しない. */
42	    now?: number;
43	  }): PendingTaskRow {
44	    const createdAt = input.now ?? Math.floor(Date.now() / 1000);
45	    const wallNow = Math.floor(Date.now() / 1000);
46	    const ttl = input.ttlSec ?? DEFAULT_TTL_SEC;
47	    const r = this.db
48	      .prepare(
49	        `INSERT INTO pending_tasks(session_id, kind, payload, created_at, delivered_at, expires_at)
50	         VALUES (?, ?, ?, ?, NULL, ?)`,
51	      )
52	      .run(input.session_id, input.kind, JSON.stringify(input.payload), createdAt, wallNow + ttl);
53	    return this.find(Number(r.lastInsertRowid))!;
54	  }
55	
56	  /**
57	   * Pull undelivered tasks for a session and mark delivered.
58	   * 返却後すぐ消費される想定 (hook の出力にしか使わない).
59	   */
60	  pull(sessionId: string, limit = 20): PendingTaskRow[] {
61	    const now = Math.floor(Date.now() / 1000);
62	    const rows = this.db
63	      .prepare(
64	        `SELECT * FROM pending_tasks
65	         WHERE session_id = ? AND delivered_at IS NULL AND expires_at > ?
66	         ORDER BY created_at ASC LIMIT ?`,
67	      )
68	      .all(sessionId, now, limit) as PendingTaskRow[];
69	    if (rows.length === 0) return [];
70	    const ids = rows.map((r) => r.id);
71	    const placeholder = ids.map(() => "?").join(",");
72	    this.db
73	      .prepare(
74	        `UPDATE pending_tasks
75	           SET delivered_at = ?, last_attempt_at = ?
76	         WHERE id IN (${placeholder})`,
77	      )
78	      .run(now, now, ...ids);
79	    return rows.map((r) => ({ ...r, delivered_at: now, last_attempt_at: now }));
80	  }
81	
82	  /**
83	   * 配信済みだが session が応答していない (= 同じ session の新規 prompt event が来てない or
84	   * 後段の chat 投稿が無い) task を retry 対象として delivered_at=NULL に戻す.
85	   *
86	   * dispatcher / sweeper から呼び出され、 「配信から retryAfterSec 秒経過、 retries < maxRetries」
87	   * の条件を満たす task を再送可能にする.
88	   *
89	   * 「応答有無」 の判断はここでは行わず、 呼び出し側が `markRespondedSince` で応答済 task を
90	   * 切り分けてから再送候補を本関数に渡す.
91	   */
92	  requeueForRetry(opts: {
93	    retryAfterSec?: number;
94	    maxRetries?: number;
95	    now?: number;
96	    kinds?: PendingTaskKind[];
97	  } = {}): PendingTaskRow[] {
98	    const now = opts.now ?? Math.floor(Date.now() / 1000);
99	    const retryAfter = opts.retryAfterSec ?? DEFAULT_RETRY_AFTER_SEC;
100	    const maxRetries = opts.maxRetries ?? DEFAULT_MAX_RETRIES;
101	    const kindFilter = opts.kinds && opts.kinds.length > 0
102	      ? ` AND kind IN (${opts.kinds.map(() => "?").join(",")})`
103	      : "";
104	    const args: unknown[] = [now - retryAfter, maxRetries, now];
105	    if (opts.kinds) args.push(...opts.kinds);
106	    const candidates = this.db
107	      .prepare(
108	        `SELECT * FROM pending_tasks
109	         WHERE delivered_at IS NOT NULL
110	           AND last_attempt_at IS NOT NULL
111	           AND last_attempt_at < ?
112	           AND retries < ?
113	           AND expires_at > ?${kindFilter}`,
114	      )
115	      .all(...args) as PendingTaskRow[];
116	    if (candidates.length === 0) return [];
117	    const ids = candidates.map((r) => r.id);
118	    const placeholder = ids.map(() => "?").join(",");
119	    this.db
120	      .prepare(
121	        `UPDATE pending_tasks
122	           SET delivered_at = NULL, retries = retries + 1
123	         WHERE id IN (${placeholder})`,
124	      )
125	      .run(...ids);
126	    return candidates.map((r) => ({ ...r, delivered_at: null, retries: r.retries + 1 }));
127	  }
128	
129	  /**
130	   * 配信済 task を「応答受信扱い」 にする (= retry 対象から外す).
131	   * delivered_at は保持しつつ retries を MAX に上げて以降 requeue されないようにする.
132	   * 「session が新 prompt event を投げた」 等で応答とみなす経路から呼ぶ.
133	   */
134	  markResponded(sessionId: string, kinds?: PendingTaskKind[], now = Math.floor(Date.now() / 1000)): number {
135	    const kindFilter = kinds && kinds.length > 0
136	      ? ` AND kind IN (${kinds.map(() => "?").join(",")})`
137	      : "";
138	    const args: unknown[] = [DEFAULT_MAX_RETRIES + 1, sessionId];
139	    if (kinds) args.push(...kinds);
140	    const r = this.db
141	      .prepare(
142	        `UPDATE pending_tasks
143	           SET retries = ?
144	         WHERE session_id = ? AND delivered_at IS NOT NULL${kindFilter}`,
145	      )
146	      .run(...args);
147	    return Number(r.changes ?? 0);
148	  }
149	
150	  /**
151	   * 指定 session で、 指定 kind の pending task が created_at >= sinceTs の範囲で
152	   * 既に存在するか (delivered/undelivered/expired 問わず).
153	   * idle stat-collect の「最後の指示以降に 1 回だけ」 抑止に使う.
154	   */
155	  hasTaskSince(sessionId: string, kind: PendingTaskKind, sinceTs: number): boolean {
156	    const row = this.db
157	      .prepare(
158	        `SELECT 1 FROM pending_tasks
159	         WHERE session_id = ? AND kind = ? AND created_at >= ?
160	         LIMIT 1`,
161	      )
162	      .get(sessionId, kind, sinceTs);
163	    return row !== undefined;
164	  }
165	
166	  /**
167	   * 指定 session の **未配信** (delivered_at IS NULL) かつ **未期限切れ** な
168	   * pending task の数. session-status-card で「Concordia から待たせている
169	   * 依頼の件数」 を表示する用途.
170	   */
171	  countUndeliveredForSession(sessionId: string, now?: number): number {
172	    const t = now ?? Math.floor(Date.now() / 1000);
173	    const row = this.db
174	      .prepare(
175	        `SELECT COUNT(*) AS n FROM pending_tasks
176	         WHERE session_id = ? AND delivered_at IS NULL AND expires_at > ?`,
177	      )
178	      .get(sessionId, t) as { n: number };
179	    return row.n;
180	  }
181	
182	  /**
183	   * 指定 session の指定 kind で「未配信 (delivered_at IS NULL) かつ未失効」 の
184	   * pending task が存在するか. stat-collect の二重 enqueue 抑止などに使う.
185	   */
186	  hasUndelivered(sessionId: string, kind: PendingTaskKind, now = Math.floor(Date.now() / 1000)): boolean {
187	    const row = this.db
188	      .prepare(
189	        `SELECT 1 FROM pending_tasks
190	         WHERE session_id = ? AND kind = ?
191	           AND delivered_at IS NULL AND expires_at > ?
192	         LIMIT 1`,
193	      )
194	      .get(sessionId, kind, now);
195	    return row !== undefined;
196	  }
197	
198	  find(id: number): PendingTaskRow | null {
199	    return (
200	      (this.db
201	        .prepare(`SELECT * FROM pending_tasks WHERE id = ?`)
202	        .get(id) as PendingTaskRow | undefined) ?? null
203	    );
204	  }
205	
206	  purgeExpired(now = Math.floor(Date.now() / 1000)): number {
207	    const r = this.db
208	      .prepare(`DELETE FROM pending_tasks WHERE expires_at < ?`)
209	      .run(now);
210	    return Number(r.changes ?? 0);
211	  }
212	}
