644	    const row = deps.pendingQuestions.findById(parsed.data.question_id);
645	    if (!row || row.session_id !== id) return c.json({ error: "not_found" }, 404);
646	    if (row.answered_at !== null) return c.json({ error: "already_answered" }, 409);
647	    const options = parsePendingQuestionOptions(row.options_json);
648	
649	    // 回答 3 形態を answer_text に正規化する (Lictor はこの text をそのまま pty へ注入):
650	    //   - other_text : 自由文をそのまま
651	    //   - answer_indices : 各 label を ", " 結合 (複数選択)
652	    //   - answer_index : 単一 label
653	    let answerText: string;
654	    let answerIndex = -1; // picker fallback 用 (Other は -1)
655	    if (parsed.data.other_text !== undefined) {
656	      answerText = parsed.data.other_text;
657	      deps.pendingQuestions.markAnsweredOther(row.id, answerText);
658	    } else if (parsed.data.answer_indices !== undefined) {
659	      const idxs = parsed.data.answer_indices;
660	      const labels = idxs.map((i) => options[i]?.label);
661	      if (labels.some((l) => !l)) return c.json({ error: "answer_index_out_of_range" }, 400);
662	      answerText = labels.join(", ");
663	      answerIndex = idxs[0];
664	      deps.pendingQuestions.markAnsweredMulti(row.id, idxs, answerText);
665	    } else {
666	      const single = parsed.data.answer_index!;
667	      const label = options[single]?.label;
668	      if (!label) return c.json({ error: "answer_index_out_of_range" }, 400);
669	      answerText = label;
670	      answerIndex = single;
671	      deps.pendingQuestions.markAnswered(row.id, single, answerText);
672	    }
673	
674	    const ts = nowSec();
675	    eventBus.emit({
676	      type: "question.answered",
677	      target_session_id: id,
678	      question_id: row.id,
679	      answer_index: answerIndex,
680	      answer_text: answerText,
681	      ts,
682	    });
683	    deps.repo.appendEvent({
684	      session_id: id,
685	      ts,
686	      kind: "question_answered",
687	      payload: { question_id: row.id, answer_index: answerIndex, answer_text: answerText },
688	    });
689	    const session = deps.repo.findSession(id)!;
690	    const initialTarget = maybeParseInitialWorkTarget(row.question, answerText, session);
691	    if (initialTarget) {
692	      const title = formatDevelopmentTitle(initialTarget);
693	      deps.repo.patchSession(id, {
694	        branch: initialTarget.branch,
695	        current_task: title.slice(0, 200),
696	      });
697	      deps.repo.mergeMetadata(id, {
698	        initial_work_target: initialTarget,
699	        initial_work_confirmed_at: ts,
700	      });
701	      deps.repo.appendEvent({
702	        session_id: id,
703	        ts,
704	        kind: "title_renamed",
705	        payload: { text: title, reason: "initial_work_selected" },
706	      });
707	      eventBus.emit({ type: "session.event", session_id: id, kind: "title_renamed", ts });
708	
709	      // 開発対象が確定したら、 残タスク取得 → 一覧提示 → 実行可否の問い合わせ を
710	      // session AI に促す指示を text inject する。 回答経路 (Discord/Slack) に依らず
711	      // 同じ流れに揃え、 「Discord は無反応 / Slack は勝手に着手」 の挙動割れを解消する。
712	      // question.answered 由来の picker キーストローク fallback が先に pty へ届くので、
