769	    // (永続化失敗は dispatcher / 監視への副作用が無いため安全)
770	    let persisted = false;
771	    try {
772	      persisted = deps.transcriptLogs.insert({
773	        session_id: id,
774	        seq: parsed.data.seq,
775	        ts,
776	        kind: parsed.data.kind,
777	        payload: parsed.data.payload,
778	      });
779	    } catch (err) {
