937	    const parsed = InjectSchema.safeParse(body);
938	    if (!parsed.success) return c.json({ error: parsed.error.message }, 400);
939	    const ts = nowSec();
940	    const src = parsed.data.source ?? null;
941	    // 人間メッセージ (source="discord:<uid>:…" / "slack:<uid>:…") なら入力者を
942	    // participants レジストリに登録し、発言者名を session.inject に載せて
