1116	function buildAdvisory(session: SessionRow, peers: SessionRow[]) {
1117	  const sameBranchPeers = peers.filter((p) => p.branch && p.branch === session.branch);
1118	  const branchConflict = sameBranchPeers.length > 0;
1119	  const shortId = session.id.slice(0, 8);
1120	  const repoBase = session.repo_path.split(/[/\\]/).pop() ?? "repo";
1121	  const worktreeCommand = branchConflict
1122	    ? `git worktree add ../${repoBase}-${shortId} ${session.branch ?? "HEAD"}`
1123	    : null;
1124	  return {
1125	    active_peer_count: peers.length,
1126	    active_peer_ids: peers.map((p) => p.id),
1127	    branch_conflict: branchConflict,
1128	    recommend_worktree: branchConflict,
1129	    worktree_command: worktreeCommand,
1130	  };
1131	}
