1134	  return {
1135	    id: s.id,
1136	    provider: s.provider,
1137	    repo_path: s.repo_path,
1138	    repo_origin: s.repo_origin,
1139	    branch: s.branch,
1140	    host: s.host,
1141	    started_at: s.started_at,
1142	    ended_at: s.ended_at,
1143	    status: s.status,
1144	    last_seen_at: s.last_seen_at,
1145	    current_task: s.current_task,
1146	    metadata: s.metadata ? safeParse(s.metadata) : null,
1147	  };
1148	}
