1150	async function proxyGet(c: { json: (body: any, status: any) => Response }, port: number, path: string): Promise<Response> {
1151	  let upstream: Response;
1152	  try {
1153	    upstream = await fetchFromLictor(port, path, { method: "GET" });
1154	  } catch (err) {
1155	    return c.json({ error: `lictor unreachable: ${(err as Error).message}` }, 502 as 502);
1156	  }
1157	  const text = await upstream.text();
1158	  let body: unknown;
1159	  try { body = JSON.parse(text); } catch { body = { raw: text }; }
1160	  return c.json(body, upstream.status as 200);
1161	}
