1163	function nowSec(): number {
1164	  return Math.floor(Date.now() / 1000);
1165	}
1166	
1167	function safeParse(s: string): unknown {
1168	  try { return JSON.parse(s); } catch { return s; }
1169	}
1170	
1171	function parseMeta(s: string | null): Record<string, any> {
1172	  if (!s) return {};
1173	  try { return JSON.parse(s); } catch { return {}; }
1174	}
