30	function autoDetectSpawnDefaultCwd(probe: ConfigProbe = {}): string {
31	  const platform = probe.platform ?? process.platform;
32	  const exists = probe.exists ?? existsSync;
33	  if (platform !== "win32") return "";
34	  try {
35	    return exists(LUDIARS_AUTO_DEFAULT_CWD) ? LUDIARS_AUTO_DEFAULT_CWD : "";
36	  } catch {
37	    return "";
38	  }
