114	/** `;` 区切りの追加ワークスペースルート列を trim + 空除去で配列化 (pure)。 */
115	function parseExtraWorkspaceRoots(raw: string | undefined): string[] {
116	  return (raw ?? "")
117	    .split(";")
118	    .map((s) => s.trim())
119	    .filter((s) => s.length > 0);
120	}
121	
122	/** 正規化パスで重複除去しつつ元の表記を保つ (先頭優先、 空は捨てる) (pure)。 */
123	export function dedupeWorkspaceRoots(roots: readonly string[]): string[] {
124	  const seen = new Set<string>();
125	  const out: string[] = [];
126	  for (const r of roots) {
127	    const t = r.trim();
128	    if (!t) continue;
129	    const key = t.replace(/\\/g, "/").replace(/\/+$/, "").toLowerCase();
130	    if (seen.has(key)) continue;
131	    seen.add(key);
132	    out.push(t);
133	  }
134	  return out;
135	}
