137	/**
138	 * bind host が loopback (= localhost からしか到達できない) かを判定する (pure)。
139	 *
140	 * 空 (unset) は既定 bind が `127.0.0.1` なので loopback 扱い。 `0.0.0.0` や `::`、
141	 * LAN IP / hostname は非 loopback。 IPv6 の角括弧表記 (`[::1]`) も剥がして判定する。
142	 */
143	export function isLoopbackHost(host: string | undefined): boolean {
144	  const h = (host ?? "").trim().toLowerCase().replace(/^\[|\]$/g, "");
145	  if (!h) return true;
146	  if (h === "localhost" || h === "::1") return true;
147	  // 127.0.0.0/8 は全て loopback。
148	  return /^127\.\d{1,3}\.\d{1,3}\.\d{1,3}$/.test(h);
149	}
