151	export function loadConfig(env = process.env, probe: ConfigProbe = {}): ConcordiaConfig {
152	  const explicitSpawnCwd = (env.CONCORDIA_SPAWN_DEFAULT_CWD ?? "").trim();
153	  const spawnDefaultCwd = explicitSpawnCwd || autoDetectSpawnDefaultCwd(probe);
154	  const githubOrg =
155	    (env.CONCORDIA_GITHUB_ORG ?? "").trim() ||
156	    (autoDetectSpawnDefaultCwd(probe) ? "LUDIARS" : "");
157	  const workspaceRoot = (env.CONCORDIA_WORKSPACE_ROOT ?? "").trim() || spawnDefaultCwd;
158	  const workspaceRoots = dedupeWorkspaceRoots([
159	    workspaceRoot,
160	    ...parseExtraWorkspaceRoots(env.CONCORDIA_WORKSPACE_ROOTS),
161	  ]);
162	  return {
163	    host: env.CONCORDIA_HOST ?? "127.0.0.1",
164	    port: Number(env.CONCORDIA_PORT ?? "17330"),
165	    adminToken: (env.CONCORDIA_ADMIN_TOKEN ?? "").trim(),
166	    dbPath: env.CONCORDIA_DB_PATH || defaultDbPath(),
167	    // Stop hook が turn 終わりごとに発火する制約があるので、 idle ≠ session 終了.
168	    // 30 分 heartbeat 無しで初めて lost にする (元 5 分は短すぎた).
169	    lostAfterSec: Number(env.CONCORDIA_LOST_AFTER_SEC ?? "1800"),
170	    abandonedAfterSec: Number(env.CONCORDIA_ABANDONED_AFTER_SEC ?? "86400"),
171	    lostPurgeAfterSec: Number(env.CONCORDIA_LOST_PURGE_AFTER_SEC ?? "1800"),
172	    purgeAfterDays: Number(env.CONCORDIA_PURGE_AFTER_DAYS ?? "90"),
173	    sweeperIntervalMs: Number(env.CONCORDIA_SWEEPER_INTERVAL_MS ?? "60000"),
174	    anthropicApiKey: env.ANTHROPIC_API_KEY ?? "",
175	    reportModel: env.CONCORDIA_REPORT_MODEL ?? "claude-haiku-4-5",
176	    maxAiRules: Number(env.CONCORDIA_MAX_AI_RULES ?? "10"),
177	    spawnDefaultCwd,
178	    workspaceRoot,
179	    workspaceRoots,
180	    githubOrg,
181	  };
182	}
