277	  private getRaw(key: string): string | null {
278	    const row = this.db.prepare(`SELECT value FROM schema_meta WHERE key = ?`).get(key) as
279	      | { value: string }
280	      | undefined;
281	    return row?.value ?? null;
282	  }
283	
284	  private setRaw(key: string, value: string): void {
285	    this.db
286	      .prepare(`INSERT OR REPLACE INTO schema_meta(key, value) VALUES (?, ?)`)
287	      .run(key, value);
288	  }
289	
290	  private getBool(key: string, fallback: boolean): boolean {
291	    const raw = this.getRaw(key);
292	    if (raw === null) return fallback;
293	    return raw === "1" || raw === "true";
294	  }
295	
296	  private setBool(key: string, value: boolean): void {
297	    this.setRaw(key, value ? "1" : "0");
298	  }
