305	/** schema_meta に入った JSON 配列文字列を string[] に復元 (壊れた値は [])。 */
306	function parseRootsJson(raw: string): string[] {
307	  try {
308	    const parsed = JSON.parse(raw) as unknown;
309	    if (Array.isArray(parsed)) return parsed.filter((v): v is string => typeof v === "string");
310	  } catch {
311	    // 壊れた値は無視。
312	  }
313	  return [];
314	}
