316	/** trim + 空除去 + 正規化パスで重複除去 (先頭優先) (pure)。 */
317	function cleanRoots(roots: readonly string[]): string[] {
318	  const seen = new Set<string>();
319	  const out: string[] = [];
320	  for (const r of roots) {
321	    const t = r.trim();
322	    if (!t) continue;
323	    const key = t.replace(/\\/g, "/").replace(/\/+$/, "").toLowerCase();
324	    if (seen.has(key)) continue;
325	    seen.add(key);
326	    out.push(t);
327	  }
328	  return out;
329	}
