77	async function startSlackBotManaged(): Promise<{ ok: boolean; status: "started" | "already_running" | "disabled" | "error"; error?: string }> {
78	  if (slackBotHandle) return { ok: true, status: "already_running" };
79	  if (!slackBotDeps) return { ok: false, status: "error", error: "slack deps not initialized" };
80	  try {
81	    const h = await startSlackBot(slackBotDeps);
82	    if (!h) return { ok: true, status: "disabled" };
83	    slackBotHandle = h;
84	    return { ok: true, status: "started" };
85	  } catch (e) {
86	    return { ok: false, status: "error", error: (e as Error).message };
87	  }
88	}
