90	async function stopSlackBotManaged(): Promise<{ ok: boolean; status: "stopped" | "already_stopped" | "error"; error?: string }> {
91	  if (!slackBotHandle) return { ok: true, status: "already_stopped" };
92	  try {
93	    await slackBotHandle.stop();
94	    slackBotHandle = null;
95	    return { ok: true, status: "stopped" };
96	  } catch (e) {
97	    return { ok: false, status: "error", error: (e as Error).message };
98	  }
99	}
