101	async function restartSlackBotManaged(): Promise<{ ok: boolean; status: "restarted" | "started" | "disabled" | "error"; error?: string }> {
102	  const stop = await stopSlackBotManaged();
103	  if (!stop.ok) return { ok: false, status: "error", error: stop.error };
104	  const start = await startSlackBotManaged();
105	  if (!start.ok) return { ok: false, status: "error", error: start.error };
106	  if (start.status === "disabled") return { ok: true, status: "disabled" };
107	  return { ok: true, status: stop.status === "already_stopped" ? "started" : "restarted" };
108	}
