143	function loadDotEnv(file: string): void {
144	  if (!existsSync(file)) return;
145	  for (const raw of readFileSync(file, "utf8").split(/\r?\n/)) {
146	    const line = raw.trim();
147	    if (!line || line.startsWith("#")) continue;
148	    const eq = line.indexOf("=");
149	    if (eq < 0) continue;
150	    const key = line.slice(0, eq).trim();
151	    let val = line.slice(eq + 1).trim();
152	    if ((val.startsWith('"') && val.endsWith('"')) || (val.startsWith("'") && val.endsWith("'"))) {
153	      val = val.slice(1, -1);
154	    }
155	    if (process.env[key] === undefined) process.env[key] = val;
156	  }
157	}
