521	      sweeper.stop();
522	      clearInterval(costSampleTimer);
523	      unsubLog();
524	      await stopDiscordBotManaged();
525	      await stopSlackBotManaged();
526	      await processManager.stopAll();
527	      ws.close();
528	      server.close();
529	      closeDb();
530	    },
531	  };
532	}
