534	function isEntrypoint(): boolean {
535	  const argv1 = process.argv[1] ?? "";
536	  if (!argv1) return false;
537	  const norm = argv1.replace(/\\/g, "/");
538	  const url = import.meta.url;
539	  return url === `file://${norm}` || url === `file:///${norm}` || url.endsWith(norm);
540	}
541	
542	if (isEntrypoint()) {
543	  startBackend().catch((err) => {
544	    log.error({ err }, "Concordia failed to start");
545	    process.exit(1);
546	  });
547	}
