204	      return c.json({ error: "invalid JSON" }, 400);
205	    }
206	    const mode: SpawnMode = body.mode === "window" ? "window" : "tab";
207	
208	    // ── template 起動経路 ─────────────────────────────────────
209	    // body.template (call_name) があれば delegation テンプレから起動する。
210	    //   - provider / model / 既定 cwd はテンプレから採用。
211	    //   - body.inject_prompt=true なら prompt を render して自動注入 (= delegation
212	    //     invoke と同じ実体)。 false (既定) なら provider+model だけの素のセッション。
213	    // loopback 信頼境界に乗るため bearer token は不要 (他 /v1/admin/* と同様)。
214	    const templateName = typeof body.template === "string" ? body.template.trim() : "";
215	    if (templateName) {
216	      const tpl = deps.delegation.findTemplateByCallName(templateName);
217	      if (!tpl) return c.json({ error: `unknown template: ${templateName}` }, 404);
218	      if (!tpl.is_active) return c.json({ error: `template inactive: ${templateName}` }, 400);
219	      const injectPrompt = body.inject_prompt === true;
220	      const tplArgs = isPlainObject(body.args) ? (body.args as Record<string, unknown>) : {};
221	      const cwdOverride = typeof body.cwd === "string" && body.cwd.trim() ? body.cwd.trim() : undefined;
222	
223	      if (injectPrompt) {
224	        // prompt 注入あり = delegation invoke 本体に委譲 (render + prompt file + env + run 記録 + --model)。
225	        const result = await deps.delegationService.invoke({
226	          call_name: tpl.call_name,
227	          args: tplArgs,
228	          cwd: cwdOverride,
229	          triggered_by: "web-spawn",
230	          spawn: true,
231	        });
232	        if (!result.ok) return c.json({ error: result.error, detail: result.details }, 400);
233	        return c.json({
234	          ok: true,
235	          pid: result.spawn_pid,
236	          command: result.spawn_command,
237	          run_id: result.run.id,
238	          injected_prompt: true,
239	        });
240	      }
241	
242	      // prompt 注入なし = provider + model だけ採用した素のセッション。
243	      // cwd: caller override → テンプレ default_cwd の `${var}` を args で展開 (auto-model の
244	      // ヒント用に resolveDelegationSpawn より先に解決)。展開後が空 / 未解決 (`${` 残存) なら
245	      // undefined にして spawnDefaultCwd に委ねる。
246	      let tplCwd: string | undefined = cwdOverride;
247	      if (!tplCwd && tpl.default_cwd) {
248	        const expanded = substituteVars(tpl.default_cwd, tplArgs).trim();
249	        tplCwd = (expanded && !expanded.includes("${")) ? expanded : undefined;
250	      }
251	      // local-LLM レーンで model="auto" なら Famulus 黒箱に選ばせる (delegation invoke と同じ。
252	      // 選択 Sonnet は Famulus 内部 = Concordia は LLM-free)。それ以外は素通し。
253	      let modelInput = tpl.model;
254	      if (tpl.target_provider === "gemma4-12" && (tpl.model ?? "").trim().toLowerCase() === "auto") {
255	        modelInput = await resolveLocalModel(tpl.model, { project: tplCwd ? basename(tplCwd) : undefined, repo: tplCwd ?? null });
256	      }
257	      // 論理 provider (gemma4-12 等) → 実 spawn に解決 (delegation invoke と同じ写像)。
258	      const spawn = resolveDelegationSpawn(tpl.target_provider, modelInput);
259	      const spawnCwd = resolveSpawnCwd(tplCwd, deps.config.spawnDefaultCwd);
260	      const result = spawnSession({
261	        provider: spawn.provider,
262	        mode,
263	        args: spawn.args.length > 0 ? spawn.args : undefined,
264	        cwd: spawnCwd,
265	        title: `tpl:${tpl.call_name}`,
266	        // gemma4-12 の LICTOR_LOCAL_MODEL 等、 spawn 解決由来の env を渡す。
267	        env: spawn.env,
268	      });
269	      if (!result.ok) return c.json({ error: result.error }, 400);
270	      // delegation_emoji を pending registry に登録。session.started 受信時に cwd で claim して metadata に焼く。
271	      recordPendingDelegationSpawn({ cwd: spawnCwd, emoji: tpl.emoji ?? null, callName: tpl.call_name });
272	      return c.json({ ok: true, pid: result.pid, command: result.command, injected_prompt: false });
273	    }
274	
275	    // ── 従来経路: provider 直接指定 ───────────────────────────
276	    const provider = (body.provider as string) ?? "claude";
277	    if (!isSpawnProvider(provider)) {
278	      return c.json(
279	        { error: `unknown provider: ${provider} (valid: ${SPAWN_PROVIDERS.join(", ")})` },
280	        400,
281	      );
282	    }
283	    const result = spawnSession({
284	      provider,
285	      mode,
286	      args: Array.isArray(body.args)
287	        ? (body.args as unknown[]).filter((x): x is string => typeof x === "string")
288	        : undefined,
289	      cwd: resolveSpawnCwd(body.cwd, deps.config.spawnDefaultCwd),
290	      title: typeof body.title === "string" ? body.title : undefined,
291	      // env は外部入力からは受け取らない (CWE-78 RCE 対策)。 spawn child に渡る env は
292	      // Concordia 内部が設定する allowlist key のみ (spawner.sanitizeSpawnEnv)。
293	    });
