548	    setTimeout(() => {
549	      // shell:true を避けてアタック面を減らす (CWE-78)。 固定コマンドだが OS shell を
550	      // 介さず、 Windows では npm.cmd を明示して直接 spawn する。
551	      const npmCmd = process.platform === "win32" ? "npm.cmd" : "npm";
552	      const child = spawn(npmCmd, ["run", "dev:backend"], {
553	        cwd: process.cwd(),
554	        detached: true,
555	        stdio: "ignore",
556	      });
557	      child.unref();
558	      setTimeout(() => process.exit(0), 200);
559	    }, 100);
