299	
300	export function ReactionWorkflowSection() {
301	  const [enabled, setEnabled] = useState<boolean | null>(null);
302	  const [maps, setMaps] = useState<ReactionMappings | null>(null);
303	  const [busy, setBusy] = useState<string | null>(null);
304	  const [error, setError] = useState<string | null>(null);
305	  const [newEmoji, setNewEmoji] = useState("");
306	  const [newAction, setNewAction] = useState("");
307	
308	  useEffect(() => { void refresh(); }, []);
309	
310	  async function refresh() {
311	    try {
312	      const [s, m] = await Promise.all([
313	        fetch("/v1/admin/reaction-workflow").then((r) => r.json()),
314	        fetch("/v1/admin/reaction-mappings").then((r) => r.json()),
315	      ]);
316	      setEnabled((s as { enabled: boolean }).enabled);
317	      setMaps(m as ReactionMappings);
318	      if (!newAction && (m as ReactionMappings).actions?.length) setNewAction((m as ReactionMappings).actions[0]);
319	      setError(null);
320	    } catch (err) { setError((err as Error).message); }
321	  }
322	
323	  async function toggle(v: boolean) {
324	    setBusy("toggle"); setError(null);
325	    try { await putJson("/v1/admin/reaction-workflow", { enabled: v }); await refresh(); }
326	    catch (err) { setError((err as Error).message); } finally { setBusy(null); }
327	  }
328	
329	  async function addMapping() {
330	    const emoji = newEmoji.trim();
331	    if (!emoji || !newAction) return;
332	    setBusy("add"); setError(null);
333	    try {
334	      await putJson("/v1/admin/reaction-mappings", { emoji, action: newAction });
335	      setNewEmoji("");
336	      await refresh();
337	    } catch (err) { setError((err as Error).message); } finally { setBusy(null); }
338	  }
339	
340	  async function removeOverride(emoji: string) {
341	    setBusy(`rm:${emoji}`); setError(null);
342	    try {
343	      const r = await fetch(`/v1/admin/reaction-mappings/${encodeURIComponent(emoji)}`, { method: "DELETE" });
344	      if (!r.ok) throw new Error(`HTTP ${r.status}`);
345	      await refresh();
346	    } catch (err) { setError((err as Error).message); } finally { setBusy(null); }
347	  }
348	
349	  // 各アクションの既定トリガ絵文字 (ヘルプ表示用)。
350	  const defaultEmojisByAction: Record<string, string[]> = {};
351	  if (maps) {
352	    for (const [emoji, action] of Object.entries(maps.defaults)) {
353	      (defaultEmojisByAction[action] ??= []).push(emoji);
354	    }
355	  }
356	
357	  // 既定 + 上書き をマージした実効写像 (表示用)。
358	  const effective: { emoji: string; action: string; source: "default" | "custom" }[] = [];
359	  if (maps) {
360	    const seen = new Set<string>();
361	    for (const [emoji, action] of Object.entries(maps.overrides)) {
362	      effective.push({ emoji, action, source: "custom" });
363	      seen.add(emoji);
364	    }
365	    for (const [emoji, action] of Object.entries(maps.defaults)) {
366	      if (!seen.has(emoji)) effective.push({ emoji, action, source: "default" });
367	    }
368	  }
369	
370	  return (
371	    <section className="space-y-3">
372	      <div>
373	        <h2 className="font-semibold text-sm">リアクションワークフロー</h2>
374	        <p className="text-subtle text-xs mt-0.5">
375	          Discord/Slack のリアクション (および単発投稿された絵文字) を「指示」として
376	          headless claude / session.inject に変換する機能の有効化と、 絵文字→アクション写像。
377	        </p>
378	      </div>
379	
380	      <ToggleRow
381	        label="リアクションワークフロー"
382	        hint="ON で 🙏/🫡/📲/👈 等のリアクション・単��絵文字が処理を起動する. デフォルト OFF (記録のみ)."
383	        value={enabled === null ? null : !enabled}
384	        onToggle={(v) => toggle(!v)}
385	        busy={busy === "toggle"}
386	        onLabel="停止中" offLabel="稼働中" onAction="稼働させる" offAction="停止する"
387	      />
388	
389	      <details className="bg-muted/40 border border-border rounded p-3">
390	        <summary className="text-sm font-medium cursor-pointer">コマンド (ワークフロー) ヘルプ — 各アクションが何をするか</summary>
391	        <p className="text-xs text-subtle mt-1">
392	          いずれも「投稿内容を変換して claude に渡す」。 既定の絵文字でトリガーされる。
393	        </p>
394	        <ul className="mt-2 space-y-2">
395	          {maps?.actions.map((a) => {
396	            const h = maps.action_help?.[a];
397	            const emojis = defaultEmojisByAction[a] ?? [];
398	            return (
399	              <li key={a} className="bg-surface border border-border rounded px-2 py-1.5">
400	                <div className="flex items-center gap-2 flex-wrap">
401	                  <span className="text-base">{emojis.join(" ") || "—"}</span>
402	                  <span className="font-mono text-xs text-accent">{a}</span>
403	                  {h?.label && <span className="text-xs font-medium">{h.label}</span>}
404	                </div>
405	                {h?.summary && <div className="text-xs text-subtle mt-0.5">{h.summary}</div>}
406	                {h?.mode && <div className="text-[11px] text-subtle mt-0.5">実行: {h.mode}</div>}
407	              </li>
408	            );
409	          })}
410	        </ul>
411	      </details>
412	
413	      <div className="bg-muted/40 border border-border rounded p-3 space-y-3">
414	        <div>
415	          <div className="text-sm font-medium">絵文字 → アクション マッピング</div>
416	          <div className="text-xs text-subtle mt-0.5">
417	            デフォルトは組み込み構成。 同じ絵文字に上書き登録すると custom が優先される。
418	          </div>
419	        </div>
420	
421	        <div className="flex items-center gap-2 flex-wrap">
422	          <input
423	            type="text" value={newEmoji} onChange={(e) => setNewEmoji(e.target.value)}
424	            placeholder="絵文字 (例 🔥)" disabled={busy === "add"}
425	            className="bg-muted border border-border rounded px-2 py-1 text-sm w-28"
426	          />
427	          <select
428	            value={newAction} onChange={(e) => setNewAction(e.target.value)} disabled={busy === "add"}
429	            className="bg-muted border border-border rounded px-2 py-1 text-sm"
430	          >
431	            {maps?.actions.map((a) => (
432	              <option key={a} value={a}>{maps.action_help?.[a]?.label ? `${a} — ${maps.action_help[a].label}` : a}</option>
433	            ))}
434	          </select>
435	          <button
436	            disabled={busy === "add" || !newEmoji.trim() || !newAction}
437	            onClick={() => void addMapping()}
438	            className="px-3 py-1 bg-accent/15 border border-accent text-accent rounded text-xs disabled:opacity-40"
439	          >追加 / 上書き</button>
440	        </div>
441	
442	        <ul className="space-y-1">
443	          {effective.map((m) => (
444	            <li key={m.emoji} className="flex items-center gap-2 text-sm bg-surface border border-border rounded px-2 py-1">
445	              <span className="text-lg w-7 text-center">{m.emoji}</span>
446	              <span className="text-subtle">→</span>
447	              <span className="font-mono text-xs" title={maps?.action_help?.[m.action]?.summary}>
448	                {m.action}{maps?.action_help?.[m.action]?.label ? ` (${maps.action_help[m.action].label})` : ""}
449	              </span>
450	              <span className={`ml-2 px-1.5 py-0.5 rounded text-[10px] border ${m.source === "custom" ? "bg-accent/20 border-accent text-accent" : "bg-muted border-border text-subtle"}`}>
451	                {m.source === "custom" ? "custom" : "default"}
452	              </span>
453	              {m.source === "custom" && (
454	                <button
455	                  disabled={busy === `rm:${m.emoji}`}
456	                  onClick={() => void removeOverride(m.emoji)}
457	                  className="ml-auto text-subtle hover:text-danger text-xs"
458	                >削除</button>
459	              )}
460	            </li>
461	          ))}
462	        </ul>
463	      </div>
464	
465	      {error && <div className="text-danger text-xs">{error}</div>}
466	    </section>
467	  );
468	}
