3	// dev 時のみ、 logs/concordia.log に追記する file destination を併設して
4	// Monitor (tail -F) からの観察を可能にする. NODE_ENV=production / CONCORDIA_LOG_FILE=0
5	// で無効化できる.
6	const level = process.env.CONCORDIA_LOG_LEVEL ?? "info";
7	const fileTargetEnabled =
8	  process.env.NODE_ENV !== "production" && process.env.CONCORDIA_LOG_FILE !== "0";
9	
10	const targets: TransportTargetOptions[] = [
11	  process.env.NODE_ENV === "production"
12	    ? { target: "pino/file", options: { destination: 1 }, level }
13	    : {
14	        target: "pino-pretty",
15	        options: { colorize: true, translateTime: "SYS:HH:MM:ss" },
16	        level,
17	      },
18	];
19	if (fileTargetEnabled) {
20	  targets.push({
21	    target: "pino/file",
22	    options: { destination: "logs/concordia.log", mkdir: true },
23	    level,
24	  });
25	}
26	
27	export const rootLogger: Logger = pino({
28	  level,
29	  transport: { targets },
30	});
31	
32	export function createChildLogger(name: string): Logger {
33	  return rootLogger.child({ name });
34	}
