4	 * `new Database(":memory:") + applyMigrations(db)` の逐語コピーを置き換える。
5	 * 生成した DB は cleanup レジストリに登録され、テスト終了後に必ず close される
6	 * (better-sqlite3 のネイティブハンドルは GC 任せにするとスイート全体で蓄積する)。
7	 */
8	
9	import Database from "better-sqlite3";
10	import { mkdtempSync, rmSync } from "node:fs";
11	import { tmpdir } from "node:os";
12	import { join } from "node:path";
13	import { applyMigrations } from "../../src/db/schema.js";
14	import { registerCleanup } from "./cleanup.js";
15	
16	export function makeTestDb(): Database.Database {
17	  const db = new Database(":memory:");
18	  applyMigrations(db);
19	  registerCleanup(() => db.close());
20	  return db;
21	}
22	
23	/** migration を適用しない生の in-memory DB (schema.test 等の migration 検証用)。 */
24	export function makeRawTestDb(): Database.Database {
25	  const db = new Database(":memory:");
26	  registerCleanup(() => db.close());
27	  return db;
28	}
29	
30	/** テスト終了後に自動削除されるテンポラリディレクトリ。 */
31	export function makeTestDir(prefix = "concordia-test-"): string {
32	  const dir = mkdtempSync(join(tmpdir(), prefix));
33	  registerCleanup(() => rmSync(dir, { recursive: true, force: true }));
34	  return dir;
35	}
