55	    if (candidates.length === 0) return;
56	    // 強制ルール: 深夜帯 (23:00–翌05:00) は event rule の発火も 1/10 に間引く.
57	    const freq = actionFrequencyMultiplier();
58	    if (freq < 1 && Math.random() >= freq) {
59	      for (const r of candidates) {
60	        deps.rules.log({ rule_id: r.id, action: "skip", actor: "engine", detail: "quiet hours throttle" });
61	      }
62	      return;
63	    }
