1	/**
2	 * Concordia dispatcher — チャット発話 / レビュー / 通知 task の発火集約.
3	 *
4	 * **チャット発話判断は完全に Concordia 側 (静的アルゴリズム)**.
5	 * AI 側は受け取った task を実行するだけで、 自分で「雑談しよう」とは判断しない.
6	 *
7	 * 静的ルール (v0.1):
8	 *  - **topic shift** (新領域に作業がスライド): 70% で 新規領域雑談 (NEW_AREA seed)
9	 *  - **work count per session が 5 の倍数** (edit + tool_call 等の作業 event): 100% で 軽レビュー
10	 *  - **完全ランダム** (低確率 5%): 純粋雑談 (PURE_CHITCHAT seed)
11	 *  - chat post 後: 他 active session に chat-reply (chitchat 30% / consultation 50%)
12	 *  - sweeper の active→lost: 全 active session に session-departed
13	 *  - DELETE /v1/sessions/:id: 当該 session に daily-report
14	 *
15	 * 強制ルール:
16	 *  - **深夜帯 (23:00–翌05:00)**: 上記の能動的な雑談 / 軽レビュー / chat-reply の
17	 *    発火頻度を一律 1/10 に抑制する (shared/quiet-hours.ts). session 離脱通知 /
18	 *    daily-report などのライフサイクル通知は対象外 (取りこぼすと困るため).
19	 */
20	
21	import type { SessionsRepo } from "./db/sessions-repo.js";
22	import type { TasksRepo } from "./db/tasks-repo.js";
23	import type { ChatChannel, ChatRepo } from "./db/chat-repo.js";
24	import type { SessionRow } from "./shared/types.js";
25	import { predictRole } from "./role/predict.js";
26	import { detectTopicShift } from "./triggers/topic-change.js";
27	import {
28	  pickNewAreaSeed,
29	  pickPureChitchatSeed,
30	  pickReviewIntroSeed,
31	} from "./triggers/seeds.js";
32	import { actionFrequencyMultiplier } from "./shared/quiet-hours.js";
33	import { createChildLogger } from "./shared/logger.js";
34	
35	const dispatcherLog = createChildLogger("dispatcher");
36	
37	const TOPIC_SHIFT_PROBABILITY = 0.7;
38	const RANDOM_CHITCHAT_PROBABILITY = 0.05;
39	const WORK_COUNT_REVIEW_PERIOD = 5;
40	const REPLY_PROBABILITY_BY_CHANNEL: Record<ChatChannel, number> = {
41	  chitchat: 0.3,
42	  consultation: 0.5,
43	  "報告": 0.8,   // 独白を見たら反応する確率高め
44	  "ぼやき": 0.2,  // 独り言。たまに誰かが拾って反応する程度の低確率
45	  system: 0,
46	};
47	
48	const WORK_KINDS = new Set(["edit", "tool_call", "task_update"]);
49	
50	/** peer-log-react は同 source から短時間連発しないよう per-source-key で cooldown する. */
51	const PEER_LOG_REACT_COOLDOWN_SEC = 60;
52	
53	/** peer-log-react で扱う log event 種別. */
54	export type LogEventKind =
55	  | "rule.add"
56	  | "rule.remove"
57	  | "rule.fire"
58	  | "session.started"
59	  | "skill.poison-spike";
60	
61	export interface LogEventInput {
62	  kind: LogEventKind;
63	  /** 発生源 session_id (あれば). この session は通知対象から除外する. */
64	  source_session_id?: string | null;
65	  /** AI が反応するときに参考にする情報. UI 表示でなく chat 投稿の素材. */
66	  summary: string;
67	  /** 関連 entity (rule_id / skill_name 等). cooldown key にも使う. */
68	  ref?: string | null;
69	  /** 任意の構造化 payload. */
70	  detail?: Record<string, unknown>;
71	}
72	
73	export interface DispatcherDeps {
74	  sessions: SessionsRepo;
75	  tasks: TasksRepo;
76	  chat: ChatRepo;
77	  rng?: () => number;
78	  /** 深夜帯判定に使う現在時刻プロバイダ. 既定はシステム時計 (テスト用に注入可). */
79	  now?: () => Date;
80	  /**
81	   * Runtime kill-switch for chat-related enqueues (chitchat-suggest,
82	   * chat-reply, peer-log-react, daily-report). When the returned value
83	   * is true, enqueue methods early-return and emit nothing. Wired from
84	   * AdminState.getChatMuted in production; tests can pass () => false.
85	   */
86	  isChatMuted?: () => boolean;
87	  /**
88	   * Runtime cost kill-switch. 日次トークン予算を超過している間は true を返し、
89	   * Concordia 発の全 dispatch (chitchat / chat-reply / review / peer-react /
90	   * session-departed / daily-report) を止める。 AdminState + CostUsageTracker
91	   * から配線する。 未指定なら常に false (= ブロックしない)。
92	   */
93	  isCostBlocked?: () => boolean;
94	}
95	
96	export class Dispatcher {
97	  private rng: () => number;
98	  private now: () => Date;
99	  /** peer-log-react cooldown 管理: key = `${kind}|${ref ?? source}` → last_dispatched_sec */
100	  private logCooldown = new Map<string, number>();
101	  /** active peer の round-robin index. 偏らせない. */
102	  private peerCursor = 0;
103	  private isChatMuted: () => boolean;
104	  private isCostBlocked: () => boolean;
105	
106	  constructor(private readonly deps: DispatcherDeps) {
107	    this.rng = deps.rng ?? Math.random;
108	    this.now = deps.now ?? (() => new Date());
109	    this.isChatMuted = deps.isChatMuted ?? (() => false);
110	    this.isCostBlocked = deps.isCostBlocked ?? (() => false);
111	  }
112	
113	  /** session_event insert 後に呼ぶ. 発火条件を全部評価する */
114	  onEventAppended(session: SessionRow, _eventCount: number): void {
115	    // chat 全停止スイッチが入っているなら chitchat / chat-reply / 雑談関連を
116	    // 一切 enqueue しない. role 推定だけ走らせて metadata 保持し、 task 列は触らない.
117	    if (this.isChatMuted() || this.isCostBlocked()) {
118	      this.refreshRole(session);
119	      return;
120	    }
121	    const recent = this.deps.sessions.recentEvents(session.id, 30);
122	    const role = this.refreshRole(session, recent);
123	    // 強制ルール: 深夜帯 (23:00–翌05:00) は能動的な発火頻度を 1/10 に抑制する.
124	    const freq = actionFrequencyMultiplier(this.now());
125	
126	    // 1. topic shift 検出 — 新領域雑談
127	    if (recent.length >= 2) {
128	      const newest = recent[0];
129	      const previous = recent.slice(1).reverse(); // 古い→新しい順
130	      if (detectTopicShift(previous, newest) && this.rng() < TOPIC_SHIFT_PROBABILITY * freq) {
131	        this.enqueueChitchat(session, role, "new-area", pickNewAreaSeed(this.rng), recent);
132	        return;
133	      }
134	    }
135	
136	    // 2. work count == n*5 — 軽レビュー (深夜帯は freq で確率的に間引く)
137	    const workCount = countWorkEvents(recent);
138	    if (workCount > 0 && workCount % WORK_COUNT_REVIEW_PERIOD === 0 && this.rng() < freq) {
139	      const total = this.deps.sessions.countEvents(session.id);
140	      this.deps.tasks.enqueue({
141	        session_id: session.id,
142	        kind: "review-summary",
143	        payload: {
144	          role,
145	          last_n: WORK_COUNT_REVIEW_PERIOD,
146	          total_events: total,
147	          recent_summary: recent.slice(0, WORK_COUNT_REVIEW_PERIOD).map(serializeEvent),
148	          intro_seed: pickReviewIntroSeed(this.rng),
149	          instructions:
150	            "直近 5 件の作業 (edit/tool_call/task_update) を 3 行で振り返る. " +
151	            "うまくいったこと / 引っかかってること / 次の手 の 3 点で chitchat channel に POST.",
152	        },
153	      });
154	      return;
155	    }
156	
157	    // 3. 完全ランダム — 純粋雑談
158	    if (this.rng() < RANDOM_CHITCHAT_PROBABILITY * freq) {
159	      this.enqueueChitchat(session, role, "pure", pickPureChitchatSeed(this.rng), recent);
160	    }
161	  }
162	
163	  onChatPosted(message: {
164	    id: number;
165	    channel: ChatChannel;
166	    session_id: string | null;
167	    text: string;
168	    author_label: string;
169	    is_actionable: boolean;
170	  }): void {
171	    if (message.channel === "system") return;
172	    // コスト予算超過中は chat-reply (AI 発話) を一切 enqueue しない。
173	    if (this.isCostBlocked()) return;
174	    // 強制ルール: 深夜帯 (23:00–翌05:00) は chat-reply の確率も 1/10 に抑制する.
175	    const freq = actionFrequencyMultiplier(this.now());
176	    const replyProb =
177	      (REPLY_PROBABILITY_BY_CHANNEL[message.channel] ?? 0) * freq;
178	
179	    const peers = this.deps.sessions.listSessions({ status: "active" });
180	    dispatcherLog.info(
181	      {
182	        message_id: message.id,
183	        source_session_id: message.session_id,
184	        channel: message.channel,
185	        author_label: message.author_label,
186	        reply_prob: replyProb,
187	        freq_multiplier: freq,
188	        active_peer_count: peers.length,
