  });
});

// 管理 API: 新コード反映用の self-restart.
// 子プロセスとして `npm run dev:backend` を detach spawn → 自分は 300ms 後に process.exit(0).
// listen socket は exit で OS が回収. 数 100ms の downtime あり (in-flight request は drop).
// loopback (127.0.0.1) でしか上がってない前提で、 追加認証は付けない.
// test 時は CONCORDIA_RESTART_DRY_RUN=1 で spawn/exit を skip.
app.post("/v1/admin/restart", (c) => {
  if (process.env.CONCORDIA_RESTART_DRY_RUN === "1") {
    return c.json({ ok: true, dry_run: true });
  }
  setTimeout(() => {
    // shell:true を避けてアタック面を減らす (CWE-78)。 固定コマンドだが OS shell を
    // 介さず、 Windows では npm.cmd を明示して直接 spawn する。
    const npmCmd = process.platform === "win32" ? "npm.cmd" : "npm";
    const child = spawn(npmCmd, ["run", "dev:backend"], {
      cwd: process.cwd(),
      detached: true,
      stdio: "ignore",
    });
    child.unref();
    setTimeout(() => process.exit(0), 200);
  }, 100);

content.content:
1	// 設定ページの各セクション。Settings.tsx が左メニューで切り替えて表示する。
2	// runtime kill switch (chat-mute / rules-enabled / proposer) は旧 Rules ページの
3	// AdminTogglesPanel から移設。reaction-workflow / workspace / Lictor は新規。
4	
5	import { useEffect, useState } from "react";
6	import { api } from "../../api.js";
7	
8	// ─── 共通 UI ────────────────────────────────────────────────────────────
9	
10	function ToggleRow(props: {
11	  label: string;
12	  hint: string;
13	  /** true = "禁止中" 側 (warn), false = "稼働中" 側 (ok), null = loading */
14	  value: boolean | null;
15	  onToggle: (next: boolean) => void;
16	  busy: boolean;
17	  onLabel: string;
18	  offLabel: string;
19	  onAction: string;
20	  offAction: string;
21	}) {
22	  const on = props.value === true;
23	  const stateLabel = props.value === null ? "..." : on ? props.onLabel : props.offLabel;
24	  const actionLabel = props.value === null ? "..." : on ? props.onAction : props.offAction;
25	  const stateClasses = props.value === null
26	    ? "bg-muted text-subtle border-border"
27	    : on ? "bg-warn/20 border-warn text-warn" : "bg-ok/20 border-ok text-ok";
28	  return (
29	    <div className="bg-muted/40 border border-border rounded p-3 space-y-2">
30	      <div>
31	        <div className="text-sm font-medium">{props.label}</div>
32	        <div className="text-xs text-subtle mt-0.5">{props.hint}</div>
33	      </div>
34	      <div className="flex items-center gap-2">
35	        <span className="text-xs text-subtle shrink-0">現在:</span>
36	        <span className={`shrink-0 px-2 py-0.5 rounded text-xs border ${stateClasses}`}>{stateLabel}</span>
37	        <button
38	          disabled={props.busy || props.value === null}
39	          onClick={() => props.onToggle(!on)}
40	          className="ml-auto shrink-0 px-2 py-1 rounded text-xs border bg-accent/15 border-accent text-accent disabled:opacity-40"
41	          title={`${stateLabel} → ${actionLabel}`}
42	        >
43	          {actionLabel}
44	        </button>
45	      </div>
46	    </div>
47	  );
48	}
49	
50	/** 1 行のテキスト設定 (現在値 + 入力 + apply)。 */
51	function TextSettingRow(props: {
52	  label: string;
53	  hint?: React.ReactNode;
54	  current: string | null;
55	  placeholder?: string;
56	  busy: boolean;
57	  onApply: (value: string) => void;
58	}) {
59	  const [draft, setDraft] = useState("");
60	  useEffect(() => { if (props.current !== null) setDraft(props.current); }, [props.current]);
61	  return (
62	    <div className="bg-muted/40 border border-border rounded p-3 space-y-2">
63	      <div>
64	        <div className="text-sm font-medium">{props.label}</div>
65	        {props.hint && <div className="text-xs text-subtle mt-0.5">{props.hint}</div>}
66	      </div>
67	      <div className="flex items-center gap-2 flex-wrap">
68	        <span className="text-xs text-subtle shrink-0">現在:</span>
69	        <span className="shrink-0 px-2 py-0.5 rounded text-xs border bg-ok/20 border-ok text-ok font-mono">
70	          {props.current !== null ? (props.current || "(未設定)") : "..."}
71	        </span>
72	        <input
73	          type="text"
74	          value={draft}
75	          onChange={(e) => setDraft(e.target.value)}
76	          disabled={props.busy}
77	          placeholder={props.placeholder}
78	          className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono flex-1 min-w-[180px]"
79	        />
80	        <button
81	          disabled={props.busy || draft === (props.current ?? "")}
82	          onClick={() => props.onApply(draft)}
83	          className="shrink-0 px-3 py-1 bg-accent/15 border border-accent text-accent rounded text-xs disabled:opacity-40"
84	        >
85	          apply
86	        </button>
87	      </div>
88	    </div>
89	  );
90	}
91	
92	/** 複数ワークスペースルートを 1 行 1 パスの textarea で編集する行。 先頭行 = プライマリ。 */
93	function MultiRootSettingRow(props: {
94	  current: string[] | null;
95	  busy: boolean;
96	  onApply: (roots: string[]) => void;
97	}) {
98	  const [draft, setDraft] = useState("");
99	  useEffect(() => {
100	    if (props.current !== null) setDraft(props.current.join("\n"));
101	  }, [props.current]);
102	  const parsed = draft.split("\n").map((s) => s.trim()).filter((s) => s.length > 0);
103	  const currentJoined = (props.current ?? []).join("\n");
104	  return (
105	    <div className="bg-muted/40 border border-border rounded p-3 space-y-2">
106	      <div>
107	        <div className="text-sm font-medium">ワークスペースルート (複数可)</div>
108	        <div className="text-xs text-subtle mt-0.5">
109	          1 行 1 パス。 先頭行がプライマリ (Memoria / Lictor の基点)。 例 <code>E:\Document\Ars</code>。
110	          空にすると config (env) 既定に戻る。
111	        </div>
112	      </div>
113	      <div className="flex flex-col gap-2">
114	        <div className="flex items-start gap-2 flex-wrap">
115	          <span className="text-xs text-subtle shrink-0 pt-1">現在:</span>
116	          <div className="flex flex-col gap-0.5">
117	            {props.current === null ? (
118	              <span className="text-xs text-subtle">...</span>
119	            ) : props.current.length === 0 ? (
120	              <span className="text-xs text-subtle">(未設定)</span>
121	            ) : (
122	              props.current.map((r, i) => (
123	                <span key={r} className="px-2 py-0.5 rounded text-xs border bg-ok/20 border-ok text-ok font-mono">
124	                  {i === 0 ? "★ " : ""}{r}
125	                </span>
126	              ))
127	            )}
128	          </div>
129	        </div>
130	        <textarea
131	          value={draft}
132	          onChange={(e) => setDraft(e.target.value)}
133	          disabled={props.busy}
134	          rows={3}
135	          placeholder={"E:\\Document\\Ars\nD:\\Other\\Workspace"}
136	          className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-full"
137	        />
138	        <button
139	          disabled={props.busy || parsed.join("\n") === currentJoined}
140	          onClick={() => props.onApply(parsed)}
141	          className="self-start px-3 py-1 bg-accent/15 border border-accent text-accent rounded text-xs disabled:opacity-40"
142	        >
143	          apply
144	        </button>
145	      </div>
146	    </div>
147	  );
148	}
149	
150	async function putJson(path: string, body: unknown): Promise<void> {
151	  const r = await fetch(path, {
152	    method: "PUT",
153	    headers: { "content-type": "application/json" },
154	    body: JSON.stringify(body),
155	  });
156	  if (!r.ok) throw new Error(`HTTP ${r.status}: ${await r.text()}`);
157	}
158	
159	// ─── ランタイム制御 (旧 Rules / AdminTogglesPanel) ───────────────────────
160	
161	export function RuntimeControlsSection() {
162	  const [chatMuted, setChatMuted] = useState<boolean | null>(null);
163	  const [rulesEnabled, setRulesEnabled] = useState<boolean | null>(null);
164	  const [intervalSec, setIntervalSec] = useState<number | null>(null);
165	  const [minSec, setMinSec] = useState<number>(60);
166	  const [maxSec, setMaxSec] = useState<number>(86400);
167	  const [intervalDraft, setIntervalDraft] = useState<string>("");
168	  const [busy, setBusy] = useState<string | null>(null);
169	  const [error, setError] = useState<string | null>(null);
170	  const [discordMsg, setDiscordMsg] = useState<string | null>(null);
171	
172	  useEffect(() => { void refreshAll(); }, []);
173	
174	  async function refreshAll() {
175	    try {
176	      const r = await fetch("/v1/admin/state");
177	      if (!r.ok) throw new Error(`HTTP ${r.status}`);
178	      const s = (await r.json()) as {
179	        chat_muted: boolean; rules_enabled: boolean; rule_proposer_interval_sec: number;
180	        proposer_interval_min_sec: number; proposer_interval_max_sec: number;
181	      };
182	      setChatMuted(s.chat_muted);
183	      setRulesEnabled(s.rules_enabled);
184	      setIntervalSec(s.rule_proposer_interval_sec);
185	      setIntervalDraft(String(s.rule_proposer_interval_sec));
186	      setMinSec(s.proposer_interval_min_sec);
187	      setMaxSec(s.proposer_interval_max_sec);
188	      setError(null);
189	    } catch (err) { setError((err as Error).message); }
190	  }
191	
192	  async function put(path: string, body: unknown, key: string) {
193	    setBusy(key); setError(null);
194	    try { await putJson(path, body); await refreshAll(); }
195	    catch (err) { setError((err as Error).message); }
196	    finally { setBusy(null); }
197	  }
198	
199	  return (
200	    <section className="space-y-3">
201	      <div>
202	        <h2 className="font-semibold text-sm">runtime kill switches</h2>
203	        <p className="text-subtle text-xs mt-0.5">
204	          dispatcher / rule engine / proposer の停止スイッチ. 即時反映 + 再起動後も維持.
205	        </p>
206	      </div>
207	
208	      <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
209	        <ToggleRow
210	          label="チャット禁止 (chat-mute)"
211	          hint="ON で chitchat / chat-reply / session-end report などを enqueue しない. デフォルト ON."
212	          value={chatMuted}
213	          onToggle={(v) => put("/v1/admin/chat-mute", { muted: v }, "chat-mute")}
214	          busy={busy === "chat-mute"}
215	          onLabel="禁止中" offLabel="稼働中" onAction="稼働させる" offAction="禁止する"
216	        />
217	        <ToggleRow
218	          label="チャットルール改善禁止 (rules-enabled)"
219	          hint="OFF で rule engine + proposer の claude 呼び出しを skip. デフォルト OFF (=禁止)."
220	          value={rulesEnabled === null ? null : !rulesEnabled}
221	          onToggle={(v) => put("/v1/admin/rules-enabled", { enabled: !v }, "rules-enabled")}
222	          busy={busy === "rules-enabled"}
223	          onLabel="禁止中" offLabel="稼働中" onAction="稼働させる" offAction="禁止する"
224	        />
225	      </div>
226	
227	      <div className="bg-muted/40 border border-border rounded p-3 space-y-2">
228	        <div>
229	          <div className="text-sm font-medium">proposer interval</div>
230	          <div className="text-xs text-subtle mt-0.5">rule proposer の tick 間隔. 範囲 [{minSec}, {maxSec}] sec.</div>
231	        </div>
232	        <div className="flex items-center gap-2 flex-wrap">
233	          <span className="text-xs text-subtle shrink-0">現在:</span>
234	          <span className="shrink-0 px-2 py-0.5 rounded text-xs border bg-ok/20 border-ok text-ok">
235	            {intervalSec !== null ? `${intervalSec}s (${Math.round(intervalSec / 60)} 分)` : "..."}
236	          </span>
237	          <input
238	            type="number" min={minSec} max={maxSec} value={intervalDraft}
239	            onChange={(e) => setIntervalDraft(e.target.value)} disabled={busy === "interval"}
240	            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-24 ml-auto"
241	          />
242	          <button
243	            disabled={busy === "interval" || intervalDraft === String(intervalSec ?? "")}
244	            onClick={() => put("/v1/admin/rule-proposer-interval", { interval_sec: Number(intervalDraft) }, "interval")}
245	            className="shrink-0 px-3 py-1 bg-accent/15 border border-accent text-accent rounded text-xs disabled:opacity-40"
246	          >apply</button>
247	        </div>
248	      </div>
249	
250	      <div className="bg-muted/40 border border-border rounded p-3 space-y-2">
251	        <div className="text-sm font-medium">Discord Bot</div>
252	        <div className="text-xs text-subtle">Discord bot のみ再起動/起動/停止します（Concordia本体は再起動しません）。</div>
253	        <div className="flex items-center gap-2">
254	          <button
255	            disabled={busy === "discord-start"}
256	            onClick={async () => {
257	              setBusy("discord-start"); setDiscordMsg(null);
258	              try { const r = await api.discordBotStart(); setDiscordMsg(`start: ${r.status}`); }
259	              catch (e) { setDiscordMsg(`start failed: ${(e as Error).message}`); } finally { setBusy(null); }
260	            }}
261	            className="px-2 py-1 rounded text-xs border bg-accent/15 border-accent text-accent disabled:opacity-40"
262	          >start</button>
263	          <button
264	            disabled={busy === "discord-stop"}
265	            onClick={async () => {
266	              setBusy("discord-stop"); setDiscordMsg(null);
267	              try { const r = await api.discordBotStop(); setDiscordMsg(`stop: ${r.status}`); }
268	              catch (e) { setDiscordMsg(`stop failed: ${(e as Error).message}`); } finally { setBusy(null); }
269	            }}
270	            className="px-2 py-1 rounded text-xs border bg-muted border-border text-subtle disabled:opacity-40"
271	          >stop</button>
272	          <button
273	            disabled={busy === "discord-restart"}
274	            onClick={async () => {
275	              setBusy("discord-restart"); setDiscordMsg(null);
276	              try { const r = await api.discordBotRestart(); setDiscordMsg(`restart: ${r.status}`); }
277	              catch (e) { setDiscordMsg(`restart failed: ${(e as Error).message}`); } finally { setBusy(null); }
278	            }}
279	            className="px-2 py-1 rounded text-xs border bg-warn/20 border-warn text-warn disabled:opacity-40"
280	          >restart</button>
281	        </div>
282	        {discordMsg && <div className="text-xs text-subtle">{discordMsg}</div>}
283	      </div>
284	
285	      {error && <div className="text-danger text-xs">{error}</div>}
286	    </section>
287	  );
288	}
289	
290	// ─── リアクションワークフロー (ON/OFF + 絵文字→アクション マッピング) ──────
291	
292	interface ActionHelp { label: string; summary: string; mode: string }
293	interface ReactionMappings {
294	  defaults: Record<string, string>;
295	  overrides: Record<string, string>;
296	  actions: string[];
297	  action_help?: Record<string, ActionHelp>;
298	}
299	
300	export function ReactionWorkflowSection() {
301	  const [enabled, setEnabled] = useState<boolean | null>(null);
302	  const [maps, setMaps] = useState<ReactionMappings | null>(null);
303	  const [busy, setBusy] = useState<string | null>(null);
304	  const [error, setError] = useState<string | null>(null);
305	  const [newEmoji, setNewEmoji] = useState("");
306	  const [newAction, setNewAction] = useState("");
307	
308	  useEffect(() => { void refresh(); }, []);
309	
310	  async function refresh() {
311	    try {
312	      const [s, m] = await Promise.all([
313	        fetch("/v1/admin/reaction-workflow").then((r) => r.json()),
314	        fetch("/v1/admin/reaction-mappings").then((r) => r.json()),
315	      ]);
316	      setEnabled((s as { enabled: boolean }).enabled);
317	      setMaps(m as ReactionMappings);
318	      if (!newAction && (m as ReactionMappings).actions?.length) setNewAction((m as ReactionMappings).actions[0]);
319	      setError(null);
320	    } catch (err) { setError((err as Error).message); }
321	  }
322	
323	  async function toggle(v: boolean) {
324	    setBusy("toggle"); setError(null);
325	    try { await putJson("/v1/admin/reaction-workflow", { enabled: v }); await refresh(); }
326	    catch (err) { setError((err as Error).message); } finally { setBusy(null); }
327	  }
328	
329	  async function addMapping() {
330	    const emoji = newEmoji.trim();
331	    if (!emoji || !newAction) return;
332	    setBusy("add"); setError(null);
333	    try {
334	      await putJson("/v1/admin/reaction-mappings", { emoji, action: newAction });
335	      setNewEmoji("");
336	      await refresh();
337	    } catch (err) { setError((err as Error).message); } finally { setBusy(null); }
338	  }
339	
340	  async function removeOverride(emoji: string) {
341	    setBusy(`rm:${emoji}`); setError(null);
342	    try {
343	      const r = await fetch(`/v1/admin/reaction-mappings/${encodeURIComponent(emoji)}`, { method: "DELETE" });
344	      if (!r.ok) throw new Error(`HTTP ${r.status}`);
345	      await refresh();
346	    } catch (err) { setError((err as Error).message); } finally { setBusy(null); }
347	  }
348	
349	  // 各アクションの既定トリガ絵文字 (ヘルプ表示用)。
350	  const defaultEmojisByAction: Record<string, string[]> = {};
351	  if (maps) {
352	    for (const [emoji, action] of Object.entries(maps.defaults)) {
353	      (defaultEmojisByAction[action] ??= []).push(emoji);
354	    }
355	  }
356	
357	  // 既定 + 上書き をマージした実効写像 (表示用)。
358	  const effective: { emoji: string; action: string; source: "default" | "custom" }[] = [];
359	  if (maps) {
360	    const seen = new Set<string>();
361	    for (const [emoji, action] of Object.entries(maps.overrides)) {
362	      effective.push({ emoji, action, source: "custom" });
363	      seen.add(emoji);
364	    }
365	    for (const [emoji, action] of Object.entries(maps.defaults)) {
366	      if (!seen.has(emoji)) effective.push({ emoji, action, source: "default" });
367	    }
368	  }
369	
370	  return (
371	    <section className="space-y-3">
372	      <div>
373	        <h2 className="font-semibold text-sm">リアクションワークフロー</h2>
374	        <p className="text-subtle text-xs mt-0.5">
375	          Discord/Slack のリアクション (および単発投稿された絵文字) を「指示」として
376	          headless claude / session.inject に変換する機能の有効化と、 絵文字→アクション写像。
377	        </p>
378	      </div>
379	
380	      <ToggleRow
381	        label="リアクションワークフロー"
382	        hint="ON で 🙏/🫡/📲/👈 等のリアクション・単発絵文字が処理を起動する. デフォルト OFF (記録のみ)."
383	        value={enabled === null ? null : !enabled}
384	        onToggle={(v) => toggle(!v)}
385	        busy={busy === "toggle"}
386	        onLabel="停止中" offLabel="稼働中" onAction="稼働させる" offAction="停止する"
387	      />
388	
389	      <details className="bg-muted/40 border border-border rounded p-3">
390	        <summary className="text-sm font-medium cursor-pointer">コマンド (ワークフロー) ヘルプ — 各アクションが何をするか</summary>
391	        <p className="text-xs text-subtle mt-1">
392	          いずれも「投稿内容を変換して claude に渡す」。 既定の絵文字でトリガーされる。
393	        </p>
394	        <ul className="mt-2 space-y-2">
395	          {maps?.actions.map((a) => {
396	            const h = maps.action_help?.[a];
397	            const emojis = defaultEmojisByAction[a] ?? [];
398	            return (
399	              <li key={a} className="bg-surface border border-border rounded px-2 py-1.5">
400	                <div className="flex items-center gap-2 flex-wrap">
401	                  <span className="text-base">{emojis.join(" ") || "—"}</span>
402	                  <span className="font-mono text-xs text-accent">{a}</span>
403	                  {h?.label && <span className="text-xs font-medium">{h.label}</span>}
404	                </div>
405	                {h?.summary && <div className="text-xs text-subtle mt-0.5">{h.summary}</div>}
406	                {h?.mode && <div className="text-[11px] text-subtle mt-0.5">実行: {h.mode}</div>}
407	              </li>
408	            );
409	          })}
410	        </ul>
411	      </details>
412	
413	      <div className="bg-muted/40 border border-border rounded p-3 space-y-3">
414	        <div>
415	          <div className="text-sm font-medium">絵文字 → アクション マッピング</div>
416	          <div className="text-xs text-subtle mt-0.5">
417	            デフォルトは組み込み構成。 同じ絵文字に上書き登録すると custom が優先される。
418	          </div>
419	        </div>
420	
421	        <div className="flex items-center gap-2 flex-wrap">
422	          <input
423	            type="text" value={newEmoji} onChange={(e) => setNewEmoji(e.target.value)}
424	            placeholder="絵文字 (例 🔥)" disabled={busy === "add"}
425	            className="bg-muted border border-border rounded px-2 py-1 text-sm w-28"
426	          />
427	          <select
428	            value={newAction} onChange={(e) => setNewAction(e.target.value)} disabled={busy === "add"}
429	            className="bg-muted border border-border rounded px-2 py-1 text-sm"
430	          >
431	            {maps?.actions.map((a) => (
432	              <option key={a} value={a}>{maps.action_help?.[a]?.label ? `${a} — ${maps.action_help[a].label}` : a}</option>
433	            ))}
434	          </select>
435	          <button
436	            disabled={busy === "add" || !newEmoji.trim() || !newAction}
437	            onClick={() => void addMapping()}
438	            className="px-3 py-1 bg-accent/15 border border-accent text-accent rounded text-xs disabled:opacity-40"
439	          >追加 / 上書き</button>
440	        </div>
441	
442	        <ul className="space-y-1">
443	          {effective.map((m) => (
444	            <li key={m.emoji} className="flex items-center gap-2 text-sm bg-surface border border-border rounded px-2 py-1">
445	              <span className="text-lg w-7 text-center">{m.emoji}</span>
446	              <span className="text-subtle">→</span>
447	              <span className="font-mono text-xs" title={maps?.action_help?.[m.action]?.summary}>
448	                {m.action}{maps?.action_help?.[m.action]?.label ? ` (${maps.action_help[m.action].label})` : ""}
449	              </span>
450	              <span className={`ml-2 px-1.5 py-0.5 rounded text-[10px] border ${m.source === "custom" ? "bg-accent/20 border-accent text-accent" : "bg-muted border-border text-subtle"}`}>
451	                {m.source === "custom" ? "custom" : "default"}
452	              </span>
453	              {m.source === "custom" && (
454	                <button
455	                  disabled={busy === `rm:${m.emoji}`}
456	                  onClick={() => void removeOverride(m.emoji)}
457	                  className="ml-auto text-subtle hover:text-danger text-xs"
458	                >削除</button>
459	              )}
460	            </li>
461	          ))}
462	        </ul>
463	      </div>
464	
465	      {error && <div className="text-danger text-xs">{error}</div>}
466	    </section>
467	  );
468	}
469	
470	// ─── ワークスペース ( workspace root + GitHub Org) ────────────────────────
471	
472	export function WorkspaceSection() {
473	  const [workspaceRoots, setWorkspaceRoots] = useState<string[] | null>(null);
474	  const [githubOrg, setGithubOrg] = useState<string | null>(null);
475	  const [busy, setBusy] = useState<string | null>(null);
476	  const [error, setError] = useState<string | null>(null);
477	
478	  useEffect(() => { void refresh(); }, []);
479	
480	  async function refresh() {
481	    try {
482	      const s = (await fetch("/v1/admin/state").then((r) => r.json())) as {
483	        workspace_roots: string[]; github_org: string;
484	      };
485	      setWorkspaceRoots(s.workspace_roots ?? []);
486	      setGithubOrg(s.github_org);
487	      setError(null);
488	    } catch (err) { setError((err as Error).message); }
489	  }
490	
491	  async function apply(path: string, body: unknown, key: string) {
492	    setBusy(key); setError(null);
493	    try { await putJson(path, body); await refresh(); }
494	    catch (err) { setError((err as Error).message); } finally { setBusy(null); }
495	  }
496	
497	  return (
498	    <section className="space-y-3">
499	      <div>
500	        <h2 className="font-semibold text-sm">ワークスペース</h2>
501	        <p className="text-subtle text-xs mt-0.5">
502	          ローカルクローン親 (リアクションWF / Work 走査の基点) と GitHub Organization。
503	          保存は schema_meta 永続化。 リアクションWF の cwd 反映は次の bot 再起動後。
504	        </p>
505	      </div>
506	      <MultiRootSettingRow
507	        current={workspaceRoots} busy={busy === "ws"}
508	        onApply={(roots) => apply("/v1/admin/workspace-roots", { workspace_roots: roots }, "ws")}
509	      />
510	      <TextSettingRow
511	        label="GitHub Organization"
512	        hint={<>例 <code>LUDIARS</code>。 PR / repo 操作の owner 解決に使う。</>}
513	        current={githubOrg} placeholder="LUDIARS" busy={busy === "org"}
514	        onApply={(v) => apply("/v1/admin/github-org", { github_org: v }, "org")}
515	      />
516	      {error && <div className="text-danger text-xs">{error}</div>}
517	    </section>
518	  );
519	}
520	
521	// ─── コスト予算 (日次トークン上限 + 超過ブロック) ────────────────────────
522	
523	export function CostBudgetSection() {
524	  const [budget, setBudget] = useState<number | null>(null);
525	  const [today, setToday] = useState<number>(0);
526	  const [blocked, setBlocked] = useState<boolean>(false);
527	  const [draft, setDraft] = useState("");
528	  const [busy, setBusy] = useState(false);
529	  const [error, setError] = useState<string | null>(null);
530	
531	  useEffect(() => { void refresh(); }, []);
532	  useEffect(() => {
533	    // 当日消費は変化するので定期的に再取得 (30s)。
534	    const t = setInterval(() => { void refresh(); }, 30_000);
535	    return () => clearInterval(t);
536	  }, []);
537	
538	  async function refresh() {
539	    try {
540	      const s = (await fetch("/v1/admin/cost-budget").then((r) => r.json())) as {
541	        daily_token_budget: number; today_tokens: number; blocked: boolean;
542	      };
543	      setBudget(s.daily_token_budget);
544	      setToday(s.today_tokens);
545	      setBlocked(s.blocked);
546	      setDraft(String(s.daily_token_budget));
547	      setError(null);
548	    } catch (err) { setError((err as Error).message); }
549	  }
550	
551	  async function apply() {
552	    const n = Number(draft);
553	    if (!Number.isFinite(n) || n < 0) { setError("0 以上の数値を入力"); return; }
554	    setBusy(true); setError(null);
555	    try {
556	      await putJson("/v1/admin/cost-budget", { daily_token_budget: Math.floor(n) });
557	      await refresh();
558	    } catch (err) { setError((err as Error).message); } finally { setBusy(false); }
559	  }
560	
561	  const pct = budget && budget > 0 ? Math.min(100, Math.round((today / budget) * 100)) : 0;
562	
563	  return (
564	    <section className="space-y-3">
565	      <div>
566	        <h2 className="font-semibold text-sm">コスト予算 (日次トークン)</h2>
567	        <p className="text-subtle text-xs mt-0.5">
568	          当日 (ローカル日) のトークン消費合計が上限に達したら、 Concordia 発の命令
569	          (新規 spawn / dispatcher 発話 / リアクションWF / rule engine) を止める。
570	          外部バッチ・別ツール起動の Claude/Codex も合算対象。 0 = 無効。
571	        </p>
572	      </div>
573	
574	      <div className="bg-muted/40 border border-border rounded p-3 space-y-2">
575	        <div className="flex items-center gap-2 flex-wrap text-xs">
576	          <span className="text-subtle">当日消費:</span>
577	          <span className="font-mono">{today.toLocaleString()} tok</span>
578	          <span className="text-subtle">/ 予算:</span>
579	          <span className="font-mono">{budget === null ? "..." : budget === 0 ? "(無効)" : budget.toLocaleString()}</span>
580	          {blocked && (
581	            <span className="px-2 py-0.5 rounded text-xs border bg-danger/20 border-danger text-danger">
582	              ⛔ ブロック中
583	            </span>
584	          )}
585	        </div>
586	        {budget !== null && budget > 0 && (
587	          <div className="h-2 w-full rounded bg-muted overflow-hidden">
588	            <div
589	              className={`h-full ${blocked ? "bg-danger" : pct >= 80 ? "bg-warn" : "bg-ok"}`}
590	              style={{ width: `${pct}%` }}
591	            />
592	          </div>
593	        )}
594	        <div className="flex items-center gap-2 flex-wrap">
595	          <span className="text-xs text-subtle shrink-0">上限 (tok):</span>
596	          <input
597	            type="number"
598	            min={0}
599	            value={draft}
600	            onChange={(e) => setDraft(e.target.value)}
601	            disabled={busy}
602	            placeholder="0 = 無効 (例 2000000)"
603	            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono flex-1 min-w-[160px]"
604	          />
605	          <button
606	            disabled={busy || draft === String(budget ?? "")}
607	            onClick={() => void apply()}
608	            className="shrink-0 px-3 py-1 bg-accent/15 border border-accent text-accent rounded text-xs disabled:opacity-40"
609	          >
610	            apply
611	          </button>
612	        </div>
613	      </div>
614	      {error && <div className="text-danger text-xs">{error}</div>}
615	    </section>
616	  );
617	}
618	
619	// ─── Lictor 起動設定 (mode + dev/prod パス) ──────────────────────────────
620	
621	export function LictorSection() {
622	  const [mode, setMode] = useState<string | null>(null);
623	  const [devPath, setDevPath] = useState<string | null>(null);
624	  const [prodExe, setProdExe] = useState<string | null>(null);
625	  const [busy, setBusy] = useState<string | null>(null);
626	  const [error, setError] = useState<string | null>(null);
627	
628	  useEffect(() => { void refresh(); }, []);
629	
630	  async function refresh() {
631	    try {
632	      const s = (await fetch("/v1/admin/lictor").then((r) => r.json())) as {
633	        lictor_mode: string; lictor_dev_path: string; lictor_prod_exe: string;
634	      };
635	      setMode(s.lictor_mode);
636	      setDevPath(s.lictor_dev_path);
637	      setProdExe(s.lictor_prod_exe);
638	      setError(null);
639	    } catch (err) { setError((err as Error).message); }
640	  }
641	
642	  async function apply(body: unknown, key: string) {
643	    setBusy(key); setError(null);
644	    try { await putJson("/v1/admin/lictor", body); await refresh(); }
645	    catch (err) { setError((err as Error).message); } finally { setBusy(null); }
646	  }
647	
648	  return (
649	    <section className="space-y-3">
650	      <div>
651	        <h2 className="font-semibold text-sm">Lictor 起動設定</h2>
652	        <p className="text-subtle text-xs mt-0.5">
653	          spawn が Lictor をどう起動するか。 auto = PATH 上の <code>lictor</code> (従来)、
654	          dev = ローカルリポを <code>node bin/lictor.mjs</code> で実行、 prod = 同梱 exe を直接実行。
655	          PATH に lictor が無く spawn に失敗する環境向け。
656	        </p>
657	      </div>
658	
659	      <div className="bg-muted/40 border border-border rounded p-3 space-y-2">
660	        <div className="text-sm font-medium">モード</div>
661	        <div className="flex items-center gap-2 flex-wrap">
662	          <span className="text-xs text-subtle shrink-0">現在:</span>
663	          <span className="shrink-0 px-2 py-0.5 rounded text-xs border bg-ok/20 border-ok text-ok font-mono">
664	            {mode ?? "..."}
665	          </span>
666	          <select
667	            value={mode ?? "auto"} onChange={(e) => apply({ lictor_mode: e.target.value }, "mode")}
668	            disabled={busy === "mode"}
669	            className="bg-muted border border-border rounded px-2 py-1 text-sm ml-auto"
670	          >
671	            <option value="auto">auto (PATH の lictor)</option>
672	            <option value="dev">dev (ローカルリポ)</option>
673	            <option value="prod">prod (同梱 exe)</option>
674	          </select>
675	        </div>
676	      </div>
677	
678	      <TextSettingRow
679	        label="dev リポパス"
680	        hint={<>dev モードで使う Lictor リポ root。 <code>node &lt;path&gt;\bin\lictor.mjs</code> を起動。</>}
681	        current={devPath} placeholder="E:\\Document\\Ars\\Lictor" busy={busy === "dev"}
682	        onApply={(v) => apply({ lictor_dev_path: v }, "dev")}
683	      />
684	      <TextSettingRow
685	        label="prod exe パス"
686	        hint={<>prod モードで使う同梱 Lictor exe (Release 公開物) の絶対パス。</>}
687	        current={prodExe} placeholder="C:\\path\\to\\lictor.exe" busy={busy === "prod"}
688	        onApply={(v) => apply({ lictor_prod_exe: v }, "prod")}
689	      />
690	      {error && <div className="text-danger text-xs">{error}</div>}
691	    </section>
692	  );
693	}
