const PROPOSER_INTERVAL_MIN = 60;
const PROPOSER_INTERVAL_MAX = 86400;

// 提案 (proposal) レートリミット: session ごとの「窓 (秒) 内の最大提案回数」。
// dispatcher が提案を enqueue する前に確認し、 窓内で上限到達なら今回をスキップ。
const DEFAULT_PROPOSAL_RL_WINDOW = 60;
const DEFAULT_PROPOSAL_RL_MAX = 5;
const PROPOSAL_RL_WINDOW_MIN = 1;
