// ── 提案レートリミット (session 別 提案回数上限) ──────────────────────
// グローバル既定 (window_sec / max) + session 個別の上書き。 dispatcher が
// 提案 enqueue 前に resolveProposalRateLimit(sessionId) で実効値を取り、
// ProposalRateLimiter が窓内カウントを判定する。 max=0 は無制限 (無効)。

/** グローバル既定のレートリミット (clamp 済)。 未設定なら 60s / 5 回。 */
getProposalRateLimit(): ProposalRateLimit {
  return {
    window_sec: this.readClampedInt(
      KEY_PROPOSAL_RL_WINDOW,
      DEFAULT_PROPOSAL_RL_WINDOW,
      PROPOSAL_RL_WINDOW_MIN,
      PROPOSAL_RL_WINDOW_MAX,
    ),
    max: this.readClampedInt(
      KEY_PROPOSAL_RL_MAX,
      DEFAULT_PROPOSAL_RL_MAX,
      PROPOSAL_RL_MAX_MIN,
      PROPOSAL_RL_MAX_MAX,
    ),
  };
}

setProposalRateLimit(value: ProposalRateLimit): void {
  const clamped = clampProposalRateLimit(value);
  this.setRaw(KEY_PROPOSAL_RL_WINDOW, String(clamped.window_sec));
  this.setRaw(KEY_PROPOSAL_RL_MAX, String(clamped.max));
}

/** session 別上書きの全件 (空なら {})。 値は clamp 済で返す。 */
getProposalRateLimitOverrides(): Record<string, ProposalRateLimit> {
  const raw = this.getRaw(KEY_PROPOSAL_RL_OVERRIDES);
  if (!raw) return {};
  try {
    const parsed = JSON.parse(raw) as unknown;
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) return {};
    const out: Record<string, ProposalRateLimit> = {};
    for (const [sid, v] of Object.entries(parsed as Record<string, unknown>)) {
      if (v && typeof v === "object") {
        const o = v as { window_sec?: unknown; max?: unknown };
        out[sid] = clampProposalRateLimit({
          window_sec: Number(o.window_sec),
          max: Number(o.max),
        });
      }
    }
    return out;
  } catch {
    return {};
  }
}

/** session 別上書きを 1 件 upsert。 */
setProposalRateLimitOverride(sessionId: string, value: ProposalRateLimit): void {
  const sid = sessionId.trim();
  if (!sid) return;
  const cur = this.getProposalRateLimitOverrides();
  cur[sid] = clampProposalRateLimit(value);
  this.setRaw(KEY_PROPOSAL_RL_OVERRIDES, JSON.stringify(cur));
}

/** session 別上書きを 1 件削除 (グローバル既定に戻す)。 */
deleteProposalRateLimitOverride(sessionId: string): void {
  const cur = this.getProposalRateLimitOverrides();
  if (!Object.prototype.hasOwnProperty.call(cur, sessionId.trim())) return;
  delete cur[sessionId.trim()];
  this.setRaw(KEY_PROPOSAL_RL_OVERRIDES, JSON.stringify(cur));
}

/** 指定 session の実効レートリミット (上書きがあればそれ、 なければグローバル既定)。 */
resolveProposalRateLimit(sessionId: string): ProposalRateLimit {
  const overrides = this.getProposalRateLimitOverrides();
  return overrides[sessionId] ?? this.getProposalRateLimit();
}

