  }

  /** dev モードのローカル Lictor リポ。 未設定なら constructor 既定。 */
  getLictorDevPath(): string {
    const raw = this.getRaw(KEY_LICTOR_DEV_PATH);
    if (raw !== null && raw.trim() !== "") return raw;
    return this.defaults.lictorDevPath ?? "";
  }

  setLictorDevPath(value: string): void {
    this.setRaw(KEY_LICTOR_DEV_PATH, value.trim());
  }

  /** prod モードの同梱 Lictor exe のパス (Release 公開物)。 */
  getLictorProdExe(): string {
    return this.getRaw(KEY_LICTOR_PROD_EXE) ?? "";
  }

  setLictorProdExe(value: string): void {
    this.setRaw(KEY_LICTOR_PROD_EXE, value.trim());
  }

  // ── コスト予算 (日次トークン上限) ────────────────────────────────────
  // 0 = 無効 (ブロックしない)。 1 以上 = その日のトークン消費合計が上限に
  // 達したら Concordia 発の命令 (spawn / dispatcher / リアクションWF / proposer)
  // を止める。 外部バッチのトークンも CostUsageTracker 経由で計上される。

  /** 日次トークン予算 (0 = 無効)。 未設定なら 0。 */
  getDailyTokenBudget(): number {
    const raw = this.getRaw(KEY_DAILY_TOKEN_BUDGET);
    if (raw === null) return 0;
    const n = Number(raw);
    return Number.isFinite(n) && n > 0 ? Math.floor(n) : 0;
  }

  setDailyTokenBudget(value: number): void {
    if (!Number.isFinite(value)) {
      throw new Error("daily_token_budget must be a finite number");
    }
    this.setRaw(KEY_DAILY_TOKEN_BUDGET, String(Math.max(0, Math.floor(value))));
  }

  // ── 提案レートリミット (session 別 提案回数上限) ──────────────────────
  // グローバル既定 (window_sec / max) + session 個別の上書き。 dispatcher が
  // 提案 enqueue 前に resolveProposalRateLimit(sessionId) で実効値を取り、
  // ProposalRateLimiter が窓内カウントを判定する。 max=0 は無制限 (無効)。

  /** グローバル既定のレートリミット (clamp 済)。 未設定なら 60s / 5 回。 */
  getProposalRateLimit(): ProposalRateLimit {
    return {
      window_sec: this.readClampedInt(
        KEY_PROPOSAL_RL_WINDOW,
        DEFAULT_PROPOSAL_RL_WINDOW,
        PROPOSAL_RL_WINDOW_MIN,
        PROPOSAL_RL_WINDOW_MAX,
      ),
      max: this.readClampedInt(
        KEY_PROPOSAL_RL_MAX,
        DEFAULT_PROPOSAL_RL_MAX,
        PROPOSAL_RL_MAX_MIN,
        PROPOSAL_RL_MAX_MAX,
      ),
    };
  }

  setProposalRateLimit(value: ProposalRateLimit): void {
    const clamped = clampProposalRateLimit(value);
    this.setRaw(KEY_PROPOSAL_RL_WINDOW, String(clamped.window_sec));
    this.setRaw(KEY_PROPOSAL_RL_MAX, String(clamped.max));
  }

  /** session 別上書きの全件 (空なら {})。 値は clamp 済で返す。 */
  getProposalRateLimitOverrides(): Record<string, ProposalRateLimit> {
    const raw = this.getRaw(KEY_PROPOSAL_RL_OVERRIDES);
    if (!raw) return {};
    try {
      const parsed = JSON.parse(raw) as unknown;
      if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) return {};
      const out: Record<string, ProposalRateLimit> = {};
      for (const [sid, v] of Object.entries(parsed as Record<string, unknown>)) {
        if (v && typeof v === "object") {
          const o = v as { window_sec?: unknown; max?: unknown };
          out[sid] = clampProposalRateLimit({
            window_sec: Number(o.window_sec),
            max: Number(o.max),
          });
        }
      }
      return out;
    } catch {
      return {};
    }
  }

  /** session 別上書きを 1 件 upsert。 */
  setProposalRateLimitOverride(sessionId: string, value: ProposalRateLimit): void {
    const sid = sessionId.trim();
    if (!sid) return;
    const cur = this.getProposalRateLimitOverrides();
    cur[sid] = clampProposalRateLimit(value);
    this.setRaw(KEY_PROPOSAL_RL_OVERRIDES, JSON.stringify(cur));
  }

  /** session 別上書きを 1 件削除 (グローバル既定に戻す)。 */
  deleteProposalRateLimitOverride(sessionId: string): void {
    const cur = this.getProposalRateLimitOverrides();
    if (!Object.prototype.hasOwnProperty.call(cur, sessionId.trim())) return;
    delete cur[sessionId.trim()];
    this.setRaw(KEY_PROPOSAL_RL_OVERRIDES, JSON.stringify(cur));
  }

  /** 指定 session の実効レートリミット (上書きがあればそれ、 なければグローバル既定)。 */
  resolveProposalRateLimit(sessionId: string): ProposalRateLimit {
    const overrides = this.getProposalRateLimitOverrides();
    return overrides[sessionId] ?? this.getProposalRateLimit();
  }

  snapshot(): {
    chat_muted: boolean;
    rules_enabled: boolean;
    rule_proposer_interval_sec: number;
    workspace_root: string;
    workspace_roots: string[];
    github_org: string;
    reaction_workflow_enabled: boolean;
    lictor_mode: LictorMode;
    lictor_dev_path: string;
    lictor_prod_exe: string;
    daily_token_budget: number;
    proposal_ratelimit: ProposalRateLimit;
    proposal_ratelimit_overrides: Record<string, ProposalRateLimit>;
  } {
    return {
      chat_muted: this.getChatMuted(),
      rules_enabled: this.getRulesEnabled(),
      rule_proposer_interval_sec: this.getRuleProposerIntervalSec(),
      workspace_root: this.getWorkspaceRoot(),
      workspace_roots: this.getWorkspaceRoots(),
      github_org: this.getGithubOrg(),
      reaction_workflow_enabled: this.getReactionWorkflowEnabled(),
      lictor_mode: this.getLictorMode(),
      lictor_dev_path: this.getLictorDevPath(),
      lictor_prod_exe: this.getLictorProdExe(),
      daily_token_budget: this.getDailyTokenBudget(),
      proposal_ratelimit: this.getProposalRateLimit(),
      proposal_ratelimit_overrides: this.getProposalRateLimitOverrides(),
    };
  }

  // ── internals ───────────────────────────────────────────────────────

  private getRaw(key: string): string | null {
    const row = this.db.prepare(`SELECT value FROM schema_meta WHERE key = ?`).get(key) as
      | { value: string }
      | undefined;
    return row?.value ?? null;
  }

  private setRaw(key: string, value: string): void {
    this.db
      .prepare(`INSERT OR REPLACE INTO schema_meta(key, value) VALUES (?, ?)`)
      .run(key, value);
  }

  private getBool(key: string, fallback: boolean): boolean {
    const raw = this.getRaw(key);
    if (raw === null) return fallback;
    return raw === "1" || raw === "true";
  }

  private setBool(key: string, value: boolean): void {
    this.setRaw(key, value ? "1" : "0");
  }

  /** schema_meta の整数値を読み、 壊れ/未設定は fallback、 範囲外は clamp。 */
  private readClampedInt(key: string, fallback: number, lo: number, hi: number): number {
    const raw = this.getRaw(key);
    if (raw === null) return fallback;
    const n = Number(raw);
    if (!Number.isFinite(n)) return fallback;
    return clamp(Math.floor(n), lo, hi);
  }
}

/** 非有限を throw し、 window/max を範囲内に丸めた値を返す (pure)。 */
function clampProposalRateLimit(value: ProposalRateLimit): ProposalRateLimit {
  if (!Number.isFinite(value.window_sec) || !Number.isFinite(value.max)) {
    throw new Error("proposal rate limit window_sec / max must be finite numbers");
  }
  return {
    window_sec: clamp(Math.floor(value.window_sec), PROPOSAL_RL_WINDOW_MIN, PROPOSAL_RL_WINDOW_MAX),
    max: clamp(Math.floor(value.max), PROPOSAL_RL_MAX_MIN, PROPOSAL_RL_MAX_MAX),
  };
}

function clamp(n: number, lo: number, hi: number): number {
  return Math.max(lo, Math.min(hi, n));
}

/** schema_meta に入った JSON 配列文字列を string[] に復元 (壊れた値は [])。 */
function parseRootsJson(raw: string): string[] {
  try {
    const parsed = JSON.parse(raw) as unknown;
    if (Array.isArray(parsed)) return parsed.filter((v): v is string => typeof v === "string");
  } catch {
    // 壊れた値は無視。
  }
  return [];
}

/** trim + 空除去 + 正規化パスで重複除去 (先頭優先) (pure)。 */
function cleanRoots(roots: readonly string[]): string[] {
  const seen = new Set<string>();
  const out: string[] = [];
  for (const r of roots) {
    const t = r.trim();
    if (!t) continue;
    const key = t.replace(/\\/g, "/").replace(/\/+$/, "").toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(t);
  }
  return out;
}

export const ADMIN_PROPOSER_INTERVAL_MIN = PROPOSER_INTERVAL_MIN;
export const ADMIN_PROPOSER_INTERVAL_MAX = PROPOSER_INTERVAL_MAX;

