/**
 * セッション別 提案 (proposal) レートリミッタ.
 *
 * dispatcher が提案 (pending task) を enqueue する直前に `tryConsume(sessionId)`
 * を呼ぶ. 窓 (window_sec) 内のカウントが上限 (max) 未満なら true を返して +1,
 * 上限に達していれば false を返して「今回の提案をスキップ」させる. 窓が明けたら
 * カウントを 0 にリセットして再開する (固定窓方式).
 *
 * 設定 (窓 / 上限 / session 上書き) は AdminState 経由で schema_meta に永続化され、
 * ここには `getConfig` で実効値が注入される (グローバル既定 or session 上書き).
 * カウンタ状態自体も schema_meta (KEY) に JSON で永続化するので、 再起動を跨いでも
 * 進行中の窓が維持される. max <= 0 / window <= 0 はレートリミット無効 (常に許可).
 */

import type Database from "better-sqlite3";
import type { ProposalRateLimit } from "./state.js";
import { createChildLogger } from "../shared/logger.js";

const log = createChildLogger("proposal-ratelimit");

/** カウンタ状態の永続化キー (schema_meta). */
const KEY_COUNTERS = "admin.proposal_ratelimit_counters";

/** 期限切れエントリを掃除する安全上限 (秒). 窓よりこれだけ古い state は破棄. */
const COUNTER_GC_AFTER_SEC = 86400;

interface CounterState {
  /** 現在の窓の開始 epoch 秒. */
  start: number;
  /** 現在の窓で許可した提案回数. */
  count: number;
}

export interface ProposalRateLimiterDeps {
  db: Database.Database;
  /** 指定 session の実効レートリミット (グローバル既定 or 上書き) を返す. */
  getConfig: (sessionId: string) => ProposalRateLimit;
  /** 現在時刻 (epoch 秒) プロバイダ. 既定はシステム時計 (テスト用に注入可). */
  now?: () => number;
}

export class ProposalRateLimiter {
  constructor(private readonly deps: ProposalRateLimiterDeps) {}

  private now(): number {
    return this.deps.now ? this.deps.now() : Math.floor(Date.now() / 1000);
  }

  /**
   * 提案を 1 件出してよいか判定する. 出してよければ窓カウントを +1 して true,
   * 窓内で上限に達していれば false (= 呼び出し側は今回の提案をスキップ).
   */
  tryConsume(sessionId: string): boolean {
    const cfg = this.deps.getConfig(sessionId);
    // 無効化 (max=0 など): レートリミットしない.
    if (cfg.max <= 0 || cfg.window_sec <= 0) return true;

    const now = this.now();
    const counters = this.read();
    const prev = counters[sessionId];

    // 窓が明けた (or 初回) ならカウントをリセットして再開.
    const state: CounterState =
      !prev || now - prev.start >= cfg.window_sec ? { start: now, count: 0 } : prev;

    if (state.count >= cfg.max) {
      // 上限到達 → スキップ. 窓開始は据え置きで、 窓明けで自然回復する.
      counters[sessionId] = state;
      this.write(counters, now);
      log.info(
        { session_id: sessionId, count: state.count, max: cfg.max, window_sec: cfg.window_sec },
        "proposal skipped: session rate limit reached",
      );
      return false;
    }

    state.count += 1;
    counters[sessionId] = state;
    this.write(counters, now);
    return true;
  }

  private read(): Record<string, CounterState> {
    const row = this.deps.db
      .prepare(`SELECT value FROM schema_meta WHERE key = ?`)
      .get(KEY_COUNTERS) as { value: string } | undefined;
    if (!row) return {};
    try {
      const parsed = JSON.parse(row.value) as unknown;
      if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
        return parsed as Record<string, CounterState>;
      }
    } catch {
      // 壊れた値は無視 (空状態扱い).
    }
    return {};
  }

  private write(counters: Record<string, CounterState>, now: number): void {
    // 長期間更新の無い session state を掃除して肥大化を防ぐ.
    for (const [sid, st] of Object.entries(counters)) {
      if (now - st.start >= COUNTER_GC_AFTER_SEC) delete counters[sid];
    }
    this.deps.db
      .prepare(`INSERT OR REPLACE INTO schema_meta(key, value) VALUES (?, ?)`)
      .run(KEY_COUNTERS, JSON.stringify(counters));
  }
}

