/**
 * セッション別 提案レートリミットのゲートを通した上で pending task を enqueue する.
 * 窓内で上限到達なら enqueue せず false を返す (理由をログ). 全ての能動的な提案
 * (chitchat / review / chat-reply / peer-log-react) はこの経路を通す.
 */
private enqueueProposal(input: {
  session_id: string;
  kind: Parameters<TasksRepo["enqueue"]>[0]["kind"];
  payload: object;
}): boolean {
  if (!this.tryConsumeProposal(input.session_id)) {
    dispatcherLog.info(
      { session_id: input.session_id, kind: input.kind },
      "dispatcher: proposal skipped (session rate limit)",
    );
    return false;
  }
  this.deps.tasks.enqueue(input);
  return true;
}

