    this.deps.tasks.enqueue({
      session_id: session.id,
      kind: "daily-report",
      payload: {
        role,
        bullets,
        instructions:
          "本日のセッション終了. ロールに沿った 1〜2 段落の感想文 (ハイライト / 引っかかり / 明日への一言) を書き、 " +
          `POST /v1/reports/${session.id}/append { "role": "${role}", "monologue": "<text>" } で追記.`,
      },
    });
  }

