// ─── 提案レートリミット (session 別 提案回数上限) ────────────────────────

interface ProposalRateLimitState {
  window_sec: number;
  max: number;
  overrides: Record<string, { window_sec: number; max: number }>;
  window_min_sec: number;
  window_max_sec: number;
  max_min: number;
  max_max: number;
}

export function ProposalRateLimitSection() {
  const [data, setData] = useState<ProposalRateLimitState | null>(null);
  const [windowDraft, setWindowDraft] = useState("");
  const [maxDraft, setMaxDraft] = useState("");
  const [ovSession, setOvSession] = useState("");
  const [ovWindow, setOvWindow] = useState("");
  const [ovMax, setOvMax] = useState("");
  const [busy, setBusy] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => { void refresh(); }, []);

  async function refresh() {
    try {
      const s = (await fetch("/v1/admin/proposal-ratelimit").then((r) => r.json())) as ProposalRateLimitState;
      setData(s);
      setWindowDraft(String(s.window_sec));
      setMaxDraft(String(s.max));
      setError(null);
    } catch (err) { setError((err as Error).message); }
  }

  async function saveGlobal() {
    const window_sec = Number(windowDraft);
    const max = Number(maxDraft);
    if (!Number.isFinite(window_sec) || !Number.isFinite(max)) { setError("数値を入力"); return; }
    setBusy("global"); setError(null);
    try { await putJson("/v1/admin/proposal-ratelimit", { window_sec, max }); await refresh(); }
    catch (err) { setError((err as Error).message); } finally { setBusy(null); }
  }

  async function addOverride() {
    const session_id = ovSession.trim();
    const window_sec = Number(ovWindow);
    const max = Number(ovMax);
    if (!session_id || !Number.isFinite(window_sec) || !Number.isFinite(max)) { setError("session_id と数値を入力"); return; }
    setBusy("override"); setError(null);
    try {
      await putJson("/v1/admin/proposal-ratelimit/override", { session_id, window_sec, max });
      setOvSession(""); setOvWindow(""); setOvMax("");
      await refresh();
    } catch (err) { setError((err as Error).message); } finally { setBusy(null); }
  }

  async function removeOverride(sessionId: string) {
    setBusy(`rm:${sessionId}`); setError(null);
    try {
      const r = await fetch(`/v1/admin/proposal-ratelimit/override/${encodeURIComponent(sessionId)}`, { method: "DELETE" });
      if (!r.ok) throw new Error(`HTTP ${r.status}`);
      await refresh();
    } catch (err) { setError((err as Error).message); } finally { setBusy(null); }
  }

  const overrideEntries = data ? Object.entries(data.overrides) : [];

  return (
    <section className="space-y-3">
      <div>
        <h2 className="font-semibold text-sm">提案レートリミット</h2>
        <p className="text-subtle text-xs mt-0.5">
          session ごとに「窓 (秒) 内に dispatcher が出せる提案 (chitchat / レビュー / chat-reply 等) の
          最大回数」 を制限する。 上限到達中の提案はスキップ (窓が明けると再開)。 max = 0 で無制限。
          保存は schema_meta 永続化で即時反映。
        </p>
      </div>

      <div className="bg-muted/40 border border-border rounded p-3 space-y-2">
        <div className="text-sm font-medium">グローバル既定</div>
        <div className="flex items-center gap-2 flex-wrap text-xs">
          <span className="text-subtle">現在:</span>
          <span className="px-2 py-0.5 rounded text-xs border bg-ok/20 border-ok text-ok font-mono">
            {data ? `${data.window_sec}s / ${data.max} 回` : "..."}
          </span>
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          <label className="text-xs text-subtle">窓 (秒)</label>
          <input
            type="number" min={data?.window_min_sec ?? 1} max={data?.window_max_sec ?? 86400}
            value={windowDraft} onChange={(e) => setWindowDraft(e.target.value)} disabled={busy === "global"}
            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-24"
          />
          <label className="text-xs text-subtle">上限</label>
          <input
            type="number" min={data?.max_min ?? 0} max={data?.max_max ?? 100000}
            value={maxDraft} onChange={(e) => setMaxDraft(e.target.value)} disabled={busy === "global"}
            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-24"
          />
          <button
            disabled={busy === "global" || (windowDraft === String(data?.window_sec ?? "") && maxDraft === String(data?.max ?? ""))}
            onClick={() => void saveGlobal()}
            className="shrink-0 px-3 py-1 bg-accent/15 border border-accent text-accent rounded text-xs disabled:opacity-40"
          >apply</button>
        </div>
      </div>

      <div className="bg-muted/40 border border-border rounded p-3 space-y-3">
        <div>
          <div className="text-sm font-medium">session 別上書き</div>
          <div className="text-xs text-subtle mt-0.5">特定 session だけ別の窓 / 上限にする。 未登録の session はグローバル既定。</div>
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          <input
            type="text" value={ovSession} onChange={(e) => setOvSession(e.target.value)}
            placeholder="session_id" disabled={busy === "override"}
            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-44"
          />
          <input
            type="number" value={ovWindow} onChange={(e) => setOvWindow(e.target.value)}
            placeholder="窓 (秒)" disabled={busy === "override"}
            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-24"
          />
          <input
            type="number" value={ovMax} onChange={(e) => setOvMax(e.target.value)}
            placeholder="上限" disabled={busy === "override"}
            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-24"
          />
          <button
            disabled={busy === "override" || !ovSession.trim() || ovWindow === "" || ovMax === ""}
            onClick={() => void addOverride()}
            className="px-3 py-1 bg-accent/15 border border-accent text-accent rounded text-xs disabled:opacity-40"
          >追加 / 上書き</button>
        </div>
        <ul className="space-y-1">
          {overrideEntries.length === 0 && <li className="text-xs text-subtle">(上書きなし)</li>}
          {overrideEntries.map(([sid, cfg]) => (
            <li key={sid} className="flex items-center gap-2 text-sm bg-surface border border-border rounded px-2 py-1">
              <span className="font-mono text-xs">{sid}</span>
              <span className="text-subtle">→</span>
              <span className="font-mono text-xs">{cfg.window_sec}s / {cfg.max} 回</span>
              <button
                disabled={busy === `rm:${sid}`}
                onClick={() => void removeOverride(sid)}
                className="ml-auto text-subtle hover:text-danger text-xs"
              >削除</button>
            </li>
          ))}
        </ul>
      </div>

      {error && <div className="text-danger text-xs">{error}</div>}
    </section>
  );
}

