it("proposal rate limit: defaults 60s/5, set/clamp/persist, override resolve", () => {
  // 既定。
  expect(env.state.getProposalRateLimit()).toEqual({ window_sec: 60, max: 5 });
  expect(env.state.getProposalRateLimitOverrides()).toEqual({});
  expect(env.state.resolveProposalRateLimit("s1")).toEqual({ window_sec: 60, max: 5 });

  // グローバル set + 永続。
  env.state.setProposalRateLimit({ window_sec: 30, max: 3 });
