import { describe, it, expect, beforeEach } from "vitest";
import { makeTestDb } from "./helpers/db.js";
import { ProposalRateLimiter } from "../src/admin/proposal-ratelimit.js";
import { AdminState } from "../src/admin/state.js";
import { SessionsRepo } from "../src/db/sessions-repo.js";
import { TasksRepo } from "../src/db/tasks-repo.js";
import { ChatRepo } from "../src/db/chat-repo.js";
import { Dispatcher } from "../src/dispatcher.js";
import type Database from "better-sqlite3";

/** 昼帯固定 (深夜帯抑制を避ける)。 */
const DAYTIME = () => new Date(2026, 4, 22, 14, 0, 0);

describe("ProposalRateLimiter", () => {
  let db: Database.Database;
  let clock: number;
  beforeEach(() => {
    db = makeTestDb();
    clock = 1000;
  });

  function limiter(cfg: { window_sec: number; max: number }) {
    return new ProposalRateLimiter({ db, getConfig: () => cfg, now: () => clock });
  }

  it("窓内で上限に達するとスキップし、 窓が明けると再開する", () => {
    const rl = limiter({ window_sec: 60, max: 2 });
    expect(rl.tryConsume("a")).toBe(true); // 1
    expect(rl.tryConsume("a")).toBe(true); // 2
    expect(rl.tryConsume("a")).toBe(false); // 上限到達 → skip
    expect(rl.tryConsume("a")).toBe(false); // 窓内は据え置きで skip 継続

    // 窓未明け (start=1000, window=60 → 1060 で明ける)。
    clock = 1059;
    expect(rl.tryConsume("a")).toBe(false);

    // 窓明け → カウントリセットで再開。
    clock = 1060;
    expect(rl.tryConsume("a")).toBe(true); // reset 後 1 回目
    expect(rl.tryConsume("a")).toBe(true); // 2 回目
    expect(rl.tryConsume("a")).toBe(false); // 再び上限
  });

  it("session ごとに独立してカウントする", () => {
    const rl = limiter({ window_sec: 60, max: 1 });
    expect(rl.tryConsume("a")).toBe(true);
    expect(rl.tryConsume("a")).toBe(false);
    // 別 session は影響を受けない。
    expect(rl.tryConsume("b")).toBe(true);
    expect(rl.tryConsume("b")).toBe(false);
  });

  it("max = 0 はレートリミット無効 (常に許可)", () => {
    const rl = limiter({ window_sec: 60, max: 0 });
    for (let i = 0; i < 10; i++) expect(rl.tryConsume("a")).toBe(true);
  });

  it("カウンタ状態が schema_meta に永続化され、 再生成しても引き継がれる", () => {
    const first = limiter({ window_sec: 60, max: 2 });
    expect(first.tryConsume("a")).toBe(true);
    expect(first.tryConsume("a")).toBe(true);
    // 同じ db を使う別インスタンスでも窓内カウントは引き継がれる。
    const second = new ProposalRateLimiter({ db, getConfig: () => ({ window_sec: 60, max: 2 }), now: () => clock });
